import type { MockInterviewTest, ScenarioQuestion } from "./scenario-questions/types";

type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const mockInterviewTests: MockInterviewTest[] = [
  {
    id: "mock-comprehensive-1",
    title: "Comprehensive New Graduate Nursing Interview",
    description: "A full-length mock interview covering behavioral, clinical, and situational questions across all major nursing competency areas. Designed to simulate a real 60-minute nursing interview.",
    category: "interview_preparation",
    difficulty: "intermediate",
    timeLimit: 60,
    supportsRandomization: true,
    questions: [
      q("mt1-1",ip,"behavioral","You are starting the interview.","Tell me about yourself and why you chose nursing.","I am a BSN-prepared new graduate with clinical experience across medical-surgical, pediatric, ICU observation, and community health settings. I chose nursing because it uniquely combines science, critical thinking, and human connection. My experience as a CNA confirmed that nursing is where I can make the greatest impact on patient outcomes every day.","Professional introduction with authentic motivation.","beginner"),
      q("mt1-2",ip,"behavioral","You are asked about strengths.","What is your greatest strength as a nurse?","My greatest strength is systematic clinical thinking. I approach every patient encounter methodically—assessing, analyzing, planning, implementing, and evaluating. This prevents me from missing important findings even during stressful situations. My clinical instructors consistently noted my thorough assessment skills.","Specific strength with evidence.","beginner"),
      q("mt1-3",ip,"behavioral","You are asked about weaknesses.","What area are you working to improve?","I sometimes struggle with delegation because I want to ensure everything meets my standards. I have been working on this by practicing clear communication of expectations, trusting my team's competence, and following up on outcomes rather than micromanaging the process.","Genuine weakness with active improvement.","beginner"),
      q("mt1-4",ip,"behavioral","You need to demonstrate teamwork.","Describe a time you worked effectively on a healthcare team.","During a code simulation, I coordinated with four team members under pressure. I took the role of medication nurse, communicated clearly using closed-loop techniques, and ensured each team member understood their assignments. Our team achieved ROSC within the target timeframe and received the highest evaluation score.","Specific teamwork with measurable outcome.","beginner"),
      q("mt1-5",ip,"clinical_judgment","A patient has chest pain radiating to the jaw with diaphoresis.","What is your priority intervention?","I would call for help, obtain a 12-lead ECG immediately, administer aspirin 325mg, establish IV access, apply oxygen if SpO2 is below 94%, obtain vital signs, and notify the physician. I would also prepare for potential cardiac catheterization. Time is myocardium—every minute of delay increases damage.","STEMI response with time urgency.","intermediate"),
      q("mt1-6",ip,"clinical_judgment","A patient on heparin has an aPTT of 120 seconds.","How would you manage a supratherapeutic aPTT?","I would hold the heparin drip, assess for signs of bleeding, notify the physician with the value, and anticipate a dose adjustment. I would check all puncture sites, urine, and stool for bleeding. I would keep protamine sulfate awareness in case of severe hemorrhage. The target aPTT is typically 1.5-2.5 times the control value.","Supratherapeutic anticoagulation management.","intermediate"),
      q("mt1-7",ip,"clinical_judgment","A patient develops sudden shortness of breath post-operatively.","What is your differential diagnosis?","Post-operative dyspnea differential includes pulmonary embolism, atelectasis, pneumothorax, fluid overload, or pneumonia. I would assess breath sounds, oxygen saturation, vital signs, and risk factors. I would position upright, apply oxygen, obtain a stat chest X-ray, and notify the surgeon. PE and pneumothorax require urgent intervention.","Post-op dyspnea differential with systematic assessment.","intermediate"),
      q("mt1-8",ws,"prioritization","You have four patients with competing needs at the start of your shift.","How would you prioritize your initial assessments?","I would see patients in order of acuity and instability risk: first the patient with new vital sign changes overnight, then the immediate post-procedure patient, then the patient with pending discharge education, and finally the stable chronic patient. I would perform brief safety checks on all patients within the first 30 minutes.","Acuity-based prioritization with safety rounding.","beginner"),
      q("mt1-9",ws,"delegation","You need to delegate tasks to a CNA at the beginning of your shift.","How would you effectively delegate morning tasks?","I would provide clear, specific instructions: 'Please obtain vital signs on all four patients by 0800. For Mr. Chen in 304, check blood glucose before breakfast. For Mrs. Williams in 306, measure intake and output carefully—she is on fluid restriction. Report any blood pressure below 90 or above 180 to me immediately.'","Specific delegation with critical parameters.","beginner"),
      q("mt1-10",ws,"patient_safety","A patient on fall precautions is found standing at the bedside without assistance.","How would you address this safety concern?","I would assist them back to a safe position, assess for any injury, reinforce the importance of using the call light before getting up, ensure the bed alarm is activated, verify non-slip footwear is available, and consider whether the current fall prevention plan needs escalation. I would document the event and reassess the fall risk score.","Immediate safety intervention with plan reassessment.","beginner"),
      q("mt1-11",ws,"medication_error","You realize a medication was given at the wrong time.","How would you handle a medication timing error?","I would assess the patient for adverse effects, determine if the timing error is clinically significant for this specific medication, adjust the next scheduled dose if needed, notify the physician, document the actual time given, and complete an incident report. I would analyze what caused the timing error and implement prevention measures.","Timing error assessment with clinical significance evaluation.","beginner"),
      q("mt1-12",ws,"handoff_communication","You are preparing to give shift report.","Walk me through your handoff process.","I use SBAR: Situation—patient name, diagnosis, and current status. Background—relevant history, overnight events, and trends. Assessment—current vital signs, recent labs, physical findings, and concerns. Recommendation—pending tasks, things to watch for, and expected orders. I also include patient preferences and family communication needs.","Structured SBAR handoff with patient preferences.","beginner"),
      q("mt1-13",ct,"first_shift","You encounter a clinical situation beyond your comfort level.","How would you handle a situation beyond your skill level?","I would recognize my limitation, ensure patient safety with immediate stabilizing measures, call for experienced help, and not attempt procedures or interventions beyond my competence. I would learn from the situation afterward. Recognizing limitations and seeking help is a sign of clinical maturity, not weakness.","Mature competence limitation recognition.","beginner"),
      q("mt1-14",ct,"time_management","Your shift is behind schedule and a new admission arrives.","How would you manage an unexpected admission when already behind?","I would triage: perform a brief safety assessment on the new admission, ensure they are settled and safe, communicate with the charge nurse about my workload, delegate appropriate tasks, and prioritize critical needs. I would not rush patient safety to catch up—I would ask for help if needed.","Admission management with workload communication.","beginner"),
      q("mt1-15",ct,"documentation_challenges","You need to document a complex clinical event.","How do you approach documentation for a complex event?","I document chronologically with specific times, objective observations, interventions taken, patient responses, and provider notifications. I use precise language and avoid subjective speculation. I ensure my documentation tells a complete clinical story that any reader could follow to understand what happened, what I did, and why.","Complete event documentation methodology.","intermediate"),
      q("mt1-16",pd,"ethical_dilemmas","A patient refuses a life-saving blood transfusion for religious reasons.","How would you manage this ethical situation?","I would ensure the patient has decision-making capacity, verify their understanding of the consequences, document the informed refusal thoroughly, respect their autonomous decision, explore alternatives with the physician, and provide emotional support. I would not impose my values. Patient autonomy must be respected even when we disagree with the decision.","Autonomy respect in life-threatening refusal.","advanced"),
      q("mt1-17",pd,"professional_boundaries","A patient asks for your social media information.","How would you handle this boundary situation?","I would decline warmly: 'I appreciate the connection we have had. However, I need to maintain professional boundaries, which means I cannot connect on social media. The best way to stay in touch with your healthcare team is through your patient portal or by contacting the unit directly.'","Professional social media boundary.","beginner"),
      q("mt1-18",pd,"advocacy","A patient does not understand their medication instructions.","How would you ensure medication comprehension?","I would use teach-back: explain each medication's purpose, dose, timing, and important side effects using plain language. Then I would ask: 'Can you tell me in your own words when you will take this medication and why?' I would re-explain anything unclear and provide written materials. I would arrange home health follow-up if complexity warrants it.","Teach-back for medication education.","beginner"),
      q("mt1-19",pd,"patient_communication","A family member is upset about the care their loved one is receiving.","How would you de-escalate a family conflict?","I would listen actively without interrupting, validate their feelings, apologize for their negative experience, provide factual information about the care being given, involve the charge nurse or patient advocate if needed, and create a communication plan. Most family anger stems from fear, and active listening diffuses it effectively.","Family conflict de-escalation.","beginner"),
      q("mt1-20",cn,"career_advancement","You are asked about your 5-year career plan.","Where do you see yourself in 5 years?","In 5 years, I see myself as a certified specialty nurse with strong clinical expertise, actively mentoring new graduates, and contributing to evidence-based practice on my unit. I plan to pursue specialty certification within 2 years and begin exploring graduate education by year 4. My immediate focus is building a strong clinical foundation.","Realistic, milestone-based career plan.","beginner"),
      q("mt1-21",ip,"clinical_judgment","A patient with diabetes has a blood glucose of 45 and is confused.","What is your immediate intervention?","Since the patient is confused and may not be able to swallow safely, I would not give oral glucose. I would administer IV dextrose 50% push if IV access is available, or IM glucagon if no IV. I would recheck glucose in 15 minutes and prepare to repeat treatment. I would investigate the cause and notify the physician.","Hypoglycemia with altered consciousness management.","intermediate"),
      q("mt1-22",ws,"difficult_coworkers","A colleague makes dismissive comments about your clinical judgment.","How would you address dismissive behavior from a peer?","I would address it privately: 'When you dismiss my clinical findings, it discourages me from speaking up about patient concerns. I have valid observations and I need them to be taken seriously. Can we discuss how we can communicate more respectfully?' If behavior continued, I would escalate with specific documented examples.","Direct communication about dismissive behavior.","intermediate"),
      q("mt1-23",ct,"critical_thinking_drills","A patient's potassium is 6.2 mEq/L.","What does critical hyperkalemia require?","Potassium of 6.2 is dangerous and can cause fatal cardiac arrhythmias. I would place the patient on continuous cardiac monitoring, obtain a stat ECG checking for peaked T waves, notify the physician immediately, and anticipate orders for calcium gluconate to stabilize cardiac membrane, insulin with glucose to drive potassium intracellularly, kayexalate, and possibly dialysis.","Hyperkalemia emergency management.","intermediate"),
      q("mt1-24",pd,"workplace_bullying","You witness a colleague being mistreated by a senior staff member.","How would you respond to witnessed workplace bullying?","I would intervene if safe to do so: 'I do not think that is appropriate.' I would check on my colleague afterward and encourage them to document and report. If I witnessed a pattern, I would report it to management myself. Bystander intervention is essential for creating a safe work environment. Silence enables bullying.","Active bystander intervention against bullying.","intermediate"),
      q("mt1-25",cn,"probation_period","Your preceptor gives you constructive criticism about your time management.","How do you respond to constructive criticism?","I would listen without defensiveness, ask for specific examples, take notes, and create an actionable improvement plan. I would say: 'Thank you for the feedback. Can you show me how you organize your workflow? I would like to incorporate your strategies.' I would follow up in a week to demonstrate improvement.","Non-defensive feedback reception with action plan.","beginner"),
      q("mt1-26",ip,"scenario_responses","A patient asks if their condition is serious.","How would you respond to questions about disease severity?","I would be honest within my scope: 'Your physician is the best person to discuss the specifics of your condition. What I can tell you is that we are monitoring you closely and providing appropriate treatment. Is there a specific concern I can address or a question I can make sure your doctor answers?'","Scope-appropriate clinical communication.","beginner"),
      q("mt1-27",ws,"interdisciplinary_communication","You disagree with a physician's order.","How would you address a questionable physician order?","I would use SBAR to express my concern: 'I want to verify this order. Based on my assessment, I am concerned that [specific finding]. The current order is [order]. I would like to discuss whether [alternative] might be more appropriate given the clinical picture.' I would escalate if needed.","Structured physician order questioning.","intermediate"),
      q("mt1-28",ct,"new_nurse_anxiety","You feel overwhelmed by the complexity of patient care.","How do you manage feeling overwhelmed?","I would take a brief mental pause, reassess my priorities, break tasks into manageable steps, and ask for help if patient safety is at risk. I would remind myself that feeling overwhelmed is normal for new nurses and temporary. I would discuss my feelings with my preceptor and seek strategies for managing complexity.","Overwhelm management with support-seeking.","beginner"),
      q("mt1-29",ip,"clinical_judgment","A patient on a ventilator develops sudden desaturation.","What is your systematic approach to ventilator desaturation?","I would use the DOPE mnemonic: Displacement of the ETT, Obstruction of the tube, Pneumothorax, Equipment failure. I would disconnect the ventilator and bag-ventilate while assessing. I would check tube position, suction for obstruction, listen for bilateral breath sounds, check equipment connections, and call for help. If unresolvable, I would prepare for reintubation.","DOPE mnemonic for ventilator troubleshooting.","advanced"),
      q("mt1-30",ws,"patient_safety","A patient is at high risk for skin breakdown.","What interventions would you implement for pressure injury prevention?","I would reposition every 2 hours, use a pressure-redistribution mattress, keep skin clean and dry, ensure adequate nutrition, minimize friction and shear, keep bed linens wrinkle-free, float heels off the bed, and perform skin assessments every shift. I would document all interventions and communicate the risk during handoff.","Comprehensive pressure injury prevention.","beginner"),
      q("mt1-31",pd,"patient_communication","A patient is anxious about an upcoming surgery.","How would you support pre-operative anxiety?","I would provide information about what to expect, encourage questions, validate their anxiety as normal, offer relaxation techniques, ensure they understand the consent, and facilitate communication with the anesthesiologist and surgeon. I would also address practical concerns: post-operative pain management, recovery timeline, and family visitation.","Multi-dimensional pre-operative anxiety support.","beginner"),
      q("mt1-32",cn,"performance_evaluation","You are asked about your goals during your evaluation.","What professional goals would you set?","I would set SMART goals: 'In the next 6 months, I will complete ACLS certification, achieve independent management of 6-patient assignments, participate in one unit committee, and complete 20 hours of CE in my specialty area. These goals support both my professional growth and the unit's staffing development needs.'","SMART professional goals with timeline.","beginner"),
      q("mt1-33",ip,"behavioral","You demonstrated leadership in a challenging situation.","Describe a time you showed leadership.","When a group project team was falling behind, I reorganized the work distribution based on each member's strengths, created a shared timeline with milestones, and facilitated weekly check-ins. We not only completed the project on time but received departmental recognition. Leadership is about enabling others to succeed, not about being in charge.","Facilitative leadership example.","beginner"),
      q("mt1-34",ws,"medication_error","A patient tells you their medication looks different from what they usually take.","How would you respond to a patient questioning medication appearance?","I would stop and verify immediately. I would check the medication against the order, contact pharmacy about possible manufacturer changes, and thank the patient for being vigilant. I would never dismiss a patient's concern about medication appearance—they are often the best safety check we have.","Patient as medication safety partner.","beginner"),
      q("mt1-35",ct,"documentation_challenges","You need to document a patient's refusal of care.","What must be included in refusal documentation?","I would document: specific care refused, education provided about risks and consequences, patient's stated reason, assessment of their decision-making capacity, alternatives offered, physician notification, and patient's continued refusal. I would have them sign a refusal form and document if they declined to sign.","Comprehensive refusal documentation.","beginner"),
      q("mt1-36",ip,"clinical_judgment","A patient develops signs of increased intracranial pressure.","What findings indicate increased ICP?","Classic signs include: Cushing's triad (hypertension, bradycardia, irregular respirations), altered consciousness, unequal pupils, headache, projectile vomiting, and papilledema. I would elevate the head of bed to 30 degrees, keep head midline, minimize stimulation, notify the neurosurgeon, and prepare for possible osmotic therapy. This is a neurosurgical emergency.","ICP emergency recognition with Cushing's triad.","advanced"),
      q("mt1-37",ws,"handoff_communication","Critical information was missed in the report you received.","How would you handle discovering omitted critical information?","I would address the clinical concern immediately—assess the patient and act on the missing information. I would contact the outgoing nurse for clarification and document my findings. I would discuss the omission constructively to prevent future gaps. Discovering gaps after handoff reinforces the importance of structured communication.","Critical information gap recovery.","intermediate"),
      q("mt1-38",pd,"ethical_dilemmas","A colleague confides they are impaired at work.","How would you handle a colleague's impairment disclosure?","I would express concern for their safety and their patients' safety. I would encourage them to seek help immediately and remove themselves from patient care. If they refused, I would report to the charge nurse for immediate intervention. Patient safety supersedes colleague loyalty. I would also provide information about peer assistance programs.","Impaired colleague intervention for patient safety.","advanced"),
      q("mt1-39",ct,"critical_thinking_drills","A patient's sodium is 125 mEq/L.","What does moderate hyponatremia indicate?","Sodium of 125 (normal 135-145) indicates moderate hyponatremia, which can cause confusion, nausea, headache, and seizures. Causes include fluid overload, SIADH, diuretics, or water intoxication. I would restrict fluids, check serum and urine osmolality, review medications, and notify the provider. Correction must be gradual to prevent osmotic demyelination syndrome.","Hyponatremia with careful correction awareness.","intermediate"),
      q("mt1-40",cn,"career_advancement","The interviewer asks what questions you have for them.","What questions would you ask at the end of an interview?","I would ask: 'What does successful orientation look like on your unit?' 'How does the unit support continued professional development?' 'What is the typical nurse-to-patient ratio?' 'Can you describe the unit culture and teamwork?' These questions demonstrate genuine interest and help me evaluate fit.","Strategic end-of-interview questions.","beginner"),
      q("mt1-41",ip,"clinical_judgment","A patient on contact isolation needs emergent defibrillation.","How do you balance infection control with emergency response?","In a life-threatening emergency, saving the patient takes absolute priority. I would don gloves and apply the defibrillator without delay for full PPE. Once the patient is stabilized, I would complete infection control measures. Emergency response cannot wait for full PPE—but I would protect myself as much as possible without delaying intervention.","Emergency prioritization over PPE in life-threatening situations.","intermediate"),
      q("mt1-42",ws,"difficult_coworkers","A colleague gossips about patients in the break room.","How would you address patient confidentiality violations?","I would redirect immediately: 'Let us be careful about discussing patient information in the break room—anyone could overhear.' I would not participate in the gossip. If the behavior is persistent, I would report it as a HIPAA concern. Patient confidentiality is a legal and ethical obligation that applies in all settings.","HIPAA violation redirection.","beginner"),
      q("mt1-43",pd,"advocacy","A patient needs a service the hospital does not provide.","How would you advocate for resources beyond your facility?","I would research community resources, contact the case manager, explore interfacility transfer if needed, and connect the patient with external organizations. I would document the unmet need and advocate through proper channels. Patient advocacy sometimes means connecting patients to services outside our walls.","Community resource advocacy beyond facility walls.","intermediate"),
      q("mt1-44",ct,"new_nurse_anxiety","You are worried about your first night shift alone.","How would you prepare for your first independent night shift?","I would prepare by reviewing all patient charts, identifying potential overnight concerns, establishing a workflow plan, introducing myself to the charge nurse and available resources, and ensuring I know emergency procedures. I would recognize that the night shift team supports each other and that asking for help is always appropriate.","First independent night shift preparation.","beginner"),
      q("mt1-45",ip,"star_examples","Describe a time you identified a patient safety concern.","Share a patient safety catch you made.","During medication reconciliation, I noticed a patient was prescribed both warfarin and aspirin with no documented indication for dual therapy. I questioned the orders with the physician who realized the aspirin was a home medication that should have been held. This catch prevented a potentially dangerous bleeding risk.","Medication safety catch through reconciliation.","intermediate"),
      q("mt1-46",ws,"patient_safety","A patient develops chest pain during a blood transfusion.","How would you respond to chest pain during transfusion?","I would stop the transfusion immediately, maintain IV access with NS, assess vital signs and oxygen saturation, obtain a 12-lead ECG, notify the physician and blood bank, and save the blood product and tubing for testing. Chest pain during transfusion could indicate hemolytic reaction, TACO, or TRALI—all requiring immediate intervention.","Transfusion chest pain emergency response.","intermediate"),
      q("mt1-47",pd,"professional_boundaries","A colleague asks you to cover for their documentation.","How would you handle a request to falsify documentation?","I would decline clearly: 'I cannot document care I did not provide. That is falsification of the medical record, which puts patients at risk and could cost both of us our licenses. If you are behind on charting, I can help you catch up, but I cannot document under my name for care I did not assess.'","Clear refusal of documentation falsification.","intermediate"),
      q("mt1-48",cn,"job_offer_negotiation","You are offered a position with a lower salary than expected.","How would you negotiate a disappointing salary offer?","I would present market data: 'I appreciate the offer. Based on my research, the market rate for BSN-prepared new graduates in this area is $X-$Y. Given my additional experience as a CNA and my specialty certifications, could we discuss adjusting the base salary? I am also interested in other compensation elements like certification reimbursement and shift differentials.'","Data-based salary negotiation.","intermediate"),
      q("mt1-49",ip,"clinical_judgment","A patient on a nitro drip has a blood pressure of 85/50.","How would you manage hypotension on a nitroglycerin drip?","I would reduce or stop the nitro drip, lower the head of bed, administer IV fluid bolus if not contraindicated, recheck blood pressure every 5 minutes, and notify the physician. I would assess for other causes of hypotension. I would not restart the drip at the same rate. Nitroglycerin-induced hypotension can compromise coronary and cerebral perfusion.","Nitro drip hypotension management.","intermediate"),
      q("mt1-50",ws,"interdisciplinary_communication","The nurse practitioner and attending disagree about a treatment plan.","How would you navigate provider disagreement?","I would ensure both perspectives are communicated and documented. I would ask for clarification: 'I want to make sure I am following the most current plan. Can you help me understand which orders are active?' I would not independently choose sides but would ensure patient care is not compromised by the disagreement.","Provider disagreement navigation.","intermediate"),
    ]
  },
  {
    id: "mock-clinical-judgment-2",
    title: "Clinical Judgment & Critical Thinking Assessment",
    description: "Focus on clinical decision-making, lab interpretation, and emergency response scenarios. Tests depth of clinical knowledge and systematic thinking.",
    category: "interview_preparation",
    difficulty: "advanced",
    timeLimit: 75,
    supportsRandomization: true,
    questions: [
      q("mt2-1",ip,"clinical_judgment","A patient in the ICU develops DIC.","How would you recognize and manage disseminated intravascular coagulation?","DIC presents with simultaneous bleeding and clotting: petechiae, oozing from IV sites, and organ dysfunction. Labs show elevated PT/PTT, decreased fibrinogen, elevated D-dimer, and decreased platelets. Management includes treating the underlying cause, blood product replacement, and supportive care. I would monitor coagulation studies frequently and assess for hemorrhage.","DIC recognition and multi-system management.","advanced"),
      q("mt2-2",ip,"clinical_judgment","A patient develops malignant hyperthermia during surgery.","What is the emergency response for malignant hyperthermia?","MH is a life-threatening reaction to anesthetic agents. I would stop triggering agents immediately, hyperventilate with 100% O2, administer dantrolene sodium, begin aggressive cooling, treat hyperkalemia, and monitor for myoglobinuria. This requires an MH cart and immediate team response. Temperature can rise 1-2°C every 5 minutes without intervention.","Malignant hyperthermia emergency protocol.","advanced"),
      q("mt2-3",ip,"clinical_judgment","A patient with liver failure develops asterixis and confusion.","What stage of hepatic encephalopathy is this?","Asterixis with confusion suggests grade II-III hepatic encephalopathy. I would check ammonia levels, initiate lactulose to promote ammonia excretion, restrict protein intake if ordered, assess for precipitating factors (GI bleeding, infection, constipation), and implement fall precautions. I would grade the encephalopathy using the West Haven criteria.","Hepatic encephalopathy grading and management.","advanced"),
      q("mt2-4",ip,"clinical_judgment","A patient on a balloon pump develops limb ischemia.","How would you assess and manage IABP limb ischemia?","I would check pedal pulses, sensation, color, temperature, and capillary refill in the catheterized limb. Absent pulses or cool, pale extremity indicates ischemia. I would notify the cardiologist immediately—the balloon may need repositioning or removal. I would document neurovascular checks every hour. Limb ischemia is a time-critical complication.","IABP limb ischemia assessment.","advanced"),
      q("mt2-5",ip,"clinical_judgment","A trauma patient has a Glasgow Coma Scale of 6.","What does a GCS of 6 indicate and what are the priorities?","GCS of 6 indicates severe brain injury. The patient likely cannot protect their airway. Priority is airway management with intubation, maintaining cerebral perfusion pressure, preventing secondary brain injury through blood pressure support, and neurosurgical evaluation. ICP monitoring may be indicated. Avoid hypotension and hypoxia—both worsen brain injury outcomes.","Severe TBI management with secondary injury prevention.","advanced"),
      q("mt2-6",ip,"clinical_judgment","A patient develops tumor lysis syndrome after chemotherapy.","How would you manage tumor lysis syndrome?","TLS causes massive cell death releasing intracellular contents: hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia. I would ensure aggressive IV hydration, administer allopurinol or rasburicase, treat hyperkalemia emergently if present, monitor renal function, and anticipate possible dialysis. Cardiac monitoring is essential due to electrolyte derangements.","Tumor lysis syndrome management.","advanced"),
      q("mt2-7",ip,"clinical_judgment","A patient with ARDS has a P/F ratio of 100.","What does this P/F ratio indicate about ARDS severity?","A PaO2/FiO2 ratio below 100 indicates severe ARDS. Management includes lung-protective ventilation (low tidal volumes 6 mL/kg), adequate PEEP, prone positioning, neuromuscular blockade if needed, and conservative fluid management. I would monitor plateau pressures, ensure they remain below 30 cmH2O, and consider ECMO referral for refractory hypoxemia.","Severe ARDS with lung-protective strategies.","advanced"),
      q("mt2-8",ip,"clinical_judgment","A patient on ECMO develops circuit clotting.","What are the signs of ECMO circuit complications?","Signs include decreased flow rates, increasing resistance, visible clots in the circuit, declining oxygenation, and hemolysis markers. I would notify the ECMO specialist immediately, check ACT levels, and prepare for possible circuit change. I would not attempt to fix circuit issues independently—ECMO management requires specialized training.","ECMO circuit complication recognition.","advanced"),
      q("mt2-9",ct,"critical_thinking_drills","A patient's ABG shows pH 7.28, pCO2 55, HCO3 24.","Interpret this ABG.","pH 7.28 is acidotic. pCO2 of 55 is elevated (respiratory acidosis). HCO3 of 24 is normal, indicating no metabolic compensation yet—this is acute respiratory acidosis. The patient is not ventilating adequately. Causes include COPD exacerbation, sedation, neuromuscular disease, or airway obstruction. I would assess respiratory status and prepare for possible ventilatory support.","Acute respiratory acidosis interpretation.","intermediate"),
      q("mt2-10",ct,"critical_thinking_drills","A patient's ABG shows pH 7.50, pCO2 30, HCO3 24.","Interpret this ABG.","pH 7.50 is alkalotic. pCO2 of 30 is low, indicating the patient is hyperventilating (respiratory alkalosis). HCO3 is normal—no metabolic compensation, so this is acute. Common causes: anxiety, pain, fever, PE, or early sepsis. I would address the underlying cause: treat pain, provide reassurance for anxiety, or evaluate for PE/sepsis.","Acute respiratory alkalosis interpretation.","intermediate"),
      q("mt2-11",ct,"critical_thinking_drills","A patient's ABG shows pH 7.32, pCO2 40, HCO3 18.","Interpret this ABG.","pH 7.32 is acidotic. pCO2 of 40 is normal. HCO3 of 18 is low, indicating metabolic acidosis without respiratory compensation. This suggests an acute process. I would calculate the anion gap to differentiate causes: elevated gap suggests DKA, lactic acidosis, or toxins; normal gap suggests diarrhea, renal tubular acidosis, or saline administration.","Metabolic acidosis with anion gap differentiation.","intermediate"),
      q("mt2-12",ip,"clinical_judgment","A patient develops neuroleptic malignant syndrome.","How would you recognize and manage NMS?","NMS presents with muscle rigidity (lead pipe), hyperthermia, altered mental status, and autonomic instability. It is caused by dopamine antagonists (antipsychotics). I would stop the offending medication, provide aggressive cooling, hydration, and dantrolene. CK levels will be markedly elevated from rhabdomyolysis. ICU monitoring is essential.","NMS emergency recognition and management.","advanced"),
      q("mt2-13",ip,"clinical_judgment","A patient with pancreatitis develops respiratory distress.","What pulmonary complication can pancreatitis cause?","Severe pancreatitis can cause ARDS through systemic inflammatory response affecting the lungs. I would monitor respiratory status closely, obtain chest X-ray, check ABG, prepare for possible intubation, and maintain aggressive fluid resuscitation while monitoring for fluid overload. The combination of pancreatitis and ARDS significantly increases mortality.","Pancreatitis-associated ARDS.","advanced"),
      q("mt2-14",ct,"critical_thinking_drills","A patient's PT is 25 seconds and INR is 3.5.","Interpret these coagulation values.","PT of 25 (normal 11-13.5) and INR of 3.5 (therapeutic range for most conditions 2.0-3.0) indicate supratherapeutic anticoagulation. The patient is at increased bleeding risk. I would hold warfarin, assess for bleeding signs, notify the provider, and anticipate dose adjustment or possible vitamin K administration for significant elevation.","Supratherapeutic anticoagulation interpretation.","intermediate"),
      q("mt2-15",ip,"clinical_judgment","A patient develops fat embolism syndrome 48 hours after a femur fracture.","How would you recognize and manage FES?","FES presents 12-72 hours after long bone fracture with the classic triad: respiratory distress, neurological changes, and petechial rash on chest/axillae. Management is supportive: oxygen therapy, mechanical ventilation if needed, maintain hemodynamics, and immobilize the fracture. There is no specific treatment—early fracture fixation reduces risk.","Fat embolism syndrome recognition and supportive care.","advanced"),
      q("mt2-16",ip,"clinical_judgment","A patient on mechanical ventilation develops auto-PEEP.","What causes auto-PEEP and how is it managed?","Auto-PEEP (breath stacking) occurs when exhalation is incomplete before the next breath—common in obstructive lung disease. It increases intrathoracic pressure, reduces venous return, and can cause hemodynamic compromise. Management includes reducing respiratory rate, increasing expiratory time, bronchodilators, and in severe cases, brief ventilator disconnect to allow complete exhalation.","Auto-PEEP recognition and ventilator management.","advanced"),
      q("mt2-17",ct,"critical_thinking_drills","A patient's mixed venous oxygen saturation is 55%.","What does a low SvO2 indicate?","Mixed venous oxygen saturation (normal 60-80%) of 55% indicates increased oxygen extraction by tissues—the body is using more oxygen than normal. This suggests inadequate oxygen delivery from low cardiac output, anemia, hypoxemia, or increased metabolic demands. I would assess cardiac function, hemoglobin, oxygenation, and for signs of shock or sepsis.","SvO2 as tissue oxygenation indicator.","advanced"),
      q("mt2-18",ip,"clinical_judgment","A patient develops a massive hemothorax after chest trauma.","How would you manage a massive hemothorax?","I would ensure two large-bore IVs, initiate massive transfusion protocol, prepare for chest tube insertion, autotransfusion if available, and notify the trauma surgeon for possible thoracotomy. A hemothorax greater than 1500 mL initial output or ongoing output >200 mL/hour may require surgical intervention. I would monitor hemodynamic status continuously.","Massive hemothorax with surgical threshold awareness.","advanced"),
      q("mt2-19",ip,"clinical_judgment","A patient in cardiogenic shock requires an intra-aortic balloon pump.","What are the nursing considerations for IABP management?","I would ensure proper timing (inflate during diastole, deflate during systole), monitor augmented diastolic pressure, check bilateral pedal pulses hourly, keep the head of bed below 30 degrees to prevent catheter migration, immobilize the cannulated leg, monitor for complications (limb ischemia, aortic dissection, thrombocytopenia), and maintain strict I&O.","IABP nursing management considerations.","advanced"),
      q("mt2-20",ip,"clinical_judgment","A patient on vasopressin, norepinephrine, and dobutamine is not improving.","What does refractory shock indicate?","Refractory shock unresponsive to multiple vasopressors suggests end-organ failure, adrenal insufficiency, or overwhelming sepsis. I would check cortisol level and consider stress-dose steroids, assess for untreated infection sources, evaluate cardiac function with echocardiography, and discuss goals of care with the team and family. Refractory shock has very high mortality.","Refractory shock evaluation and escalation.","advanced"),
      q("mt2-21",ct,"critical_thinking_drills","A patient's fibrinogen level is 80 mg/dL.","What does a critically low fibrinogen indicate?","Fibrinogen below 100 mg/dL (normal 200-400) indicates severe coagulation factor depletion, often seen in DIC, massive hemorrhage, or severe liver disease. The patient is at high risk for uncontrollable bleeding. I would anticipate cryoprecipitate transfusion, monitor for hemorrhage, check other coagulation studies, and ensure blood products are available.","Critical fibrinogen deficiency management.","advanced"),
      q("mt2-22",ip,"clinical_judgment","A post-cardiac surgery patient develops cardiac tamponade.","How would you recognize post-surgical tamponade?","Post-surgical tamponade presents with decreasing cardiac output, hypotension, elevated CVP, muffled heart sounds, equalization of chamber pressures, and decreased chest tube output (suggesting clotting). This is a surgical emergency requiring return to the OR or bedside sternotomy. I would have the resuscitation cart at bedside and notify the surgeon immediately.","Post-surgical tamponade recognition.","advanced"),
      q("mt2-23",ct,"critical_thinking_drills","A patient's serum osmolality is 320 mOsm/kg.","What does elevated serum osmolality indicate?","Serum osmolality of 320 (normal 275-295) indicates hyperosmolarity from dehydration, hypernatremia, hyperglycemia, or toxic ingestion. I would assess hydration status, check sodium and glucose levels, calculate the osmolal gap (difference between measured and calculated osmolality—if elevated, suggests toxic alcohol ingestion), and provide appropriate fluid resuscitation.","Hyperosmolarity assessment with osmolal gap.","advanced"),
      q("mt2-24",ip,"clinical_judgment","A patient develops abdominal compartment syndrome.","How would you recognize and manage abdominal compartment syndrome?","ACS presents with tense distended abdomen, decreased urine output, elevated peak airway pressures, and hemodynamic instability. Intra-abdominal pressure measured via bladder pressure exceeding 20 mmHg with organ dysfunction confirms ACS. Emergency decompressive laparotomy is the definitive treatment. I would monitor bladder pressures, report trends, and prepare for surgical intervention.","Abdominal compartment syndrome recognition.","advanced"),
      q("mt2-25",ip,"clinical_judgment","A patient on therapeutic hypothermia after cardiac arrest is being rewarmed.","What are the risks during rewarming from therapeutic hypothermia?","Rewarming carries risks of: rebound hyperthermia, electrolyte shifts (especially potassium), hemodynamic instability, seizures, and cerebral edema. I would rewarm slowly (0.25-0.5°C/hour), monitor electrolytes every 2-4 hours, maintain continuous EEG if available, manage shivering, and be prepared for complications. The rewarming phase can be more dangerous than the cooling phase.","Therapeutic hypothermia rewarming management.","advanced"),
      q("mt2-26",ct,"critical_thinking_drills","A patient's phosphorus level is 1.0 mg/dL.","What does severe hypophosphatemia cause?","Phosphorus of 1.0 (normal 2.5-4.5) is critically low. Phosphorus is essential for ATP production, and severe deficiency causes respiratory failure from diaphragm weakness, cardiac dysfunction, rhabdomyolysis, seizures, and hemolytic anemia. I would administer IV phosphorus replacement slowly, monitor calcium closely (reciprocal relationship), and identify the cause.","Critical hypophosphatemia with multi-system effects.","advanced"),
      q("mt2-27",ip,"clinical_judgment","A burn patient requires fluid resuscitation using the Parkland formula.","How would you calculate and manage burn fluid resuscitation?","The Parkland formula: 4 mL × body weight (kg) × %TBSA burned. Half is given in the first 8 hours from time of burn, the remaining half over the next 16 hours. I would titrate to urine output of 0.5-1 mL/kg/hr. I would monitor for fluid overload, abdominal compartment syndrome, and airway edema. Fluid management is the cornerstone of burn resuscitation.","Parkland formula with monitoring parameters.","advanced"),
      q("mt2-28",ct,"critical_thinking_drills","A patient's central venous pressure is 18 mmHg.","What does elevated CVP indicate?","CVP of 18 (normal 2-6 mmHg) indicates elevated right atrial pressure from fluid overload, right heart failure, cardiac tamponade, tension pneumothorax, or pulmonary hypertension. I would assess for signs of the underlying cause, check JVD, listen for lung crackles, and correlate with other hemodynamic parameters. CVP alone does not determine fluid responsiveness.","CVP interpretation with clinical correlation.","advanced"),
      q("mt2-29",ip,"clinical_judgment","A patient on a continuous vasopressin infusion needs the drip restarted after a tubing change.","What safety considerations exist for vasopressor drip management?","I would ensure the new tubing is primed, verify the concentration and rate match the order, use a dedicated central line lumen if possible, have the old drip running until the new one is verified, minimize any gap in infusion, and monitor blood pressure closely during the transition. Any interruption in vasopressor delivery can cause precipitous hemodynamic collapse.","Vasopressor drip transition safety.","advanced"),
      q("mt2-30",ip,"clinical_judgment","A patient with a pulmonary artery catheter has a cardiac output of 2.5 L/min.","What does a low cardiac output indicate?","Cardiac output of 2.5 L/min (normal 4-8) indicates severely reduced heart function. I would assess the cardiac index (CO/BSA), check SVR, evaluate volume status, and correlate with the patient's symptoms. Causes include cardiogenic shock, hypovolemia, or cardiac tamponade. Treatment depends on the underlying mechanism—inotropes for pump failure, volume for hypovolemia.","Low cardiac output assessment and management.","advanced"),
      q("mt2-31",ct,"critical_thinking_drills","A patient's ammonia level is 150 mcg/dL.","What does severely elevated ammonia indicate?","Ammonia of 150 (normal 15-45) indicates severe hepatic encephalopathy risk. The liver cannot clear ammonia from protein metabolism. I would initiate lactulose therapy (target 2-3 soft stools daily), restrict dietary protein if ordered, assess neurological status using the West Haven criteria, identify and treat precipitating factors, and consider rifaximin as adjunct therapy.","Severe hyperammonemia management.","advanced"),
      q("mt2-32",ip,"clinical_judgment","A patient develops air embolism during central line removal.","How would you manage an air embolism?","I would immediately place the patient in left lateral Trendelenburg position to trap air in the right ventricle, apply 100% oxygen, notify the physician, and aspirate air through the central line if still accessible. I would ensure all central line ports were clamped during removal and the site was sealed with an occlusive dressing. Prevention is key.","Air embolism emergency management.","advanced"),
      q("mt2-33",ip,"clinical_judgment","A patient receiving massive transfusion develops citrate toxicity.","How does citrate toxicity from blood products manifest?","Citrate in stored blood products binds calcium, causing hypocalcemia during massive transfusion. Symptoms include perioral tingling, muscle tremors, hypotension, and cardiac arrhythmias. I would monitor ionized calcium every 4-6 units transfused, administer calcium gluconate as ordered, and watch for ECG changes. The liver normally metabolizes citrate, but massive transfusion overwhelms clearance.","Massive transfusion citrate toxicity management.","advanced"),
      q("mt2-34",ct,"critical_thinking_drills","A patient's urine output suddenly increases to 300 mL/hour.","What causes sudden polyuria?","Sudden polyuria can indicate: diabetes insipidus (central or nephrogenic), post-obstructive diuresis, mannitol effect, hyperglycemic osmotic diuresis, or early renal recovery after AKI. I would check serum sodium and osmolality, urine specific gravity, and glucose. I would ensure adequate fluid replacement to prevent dangerous dehydration and hypernatremia.","Polyuria differential with fluid balance management.","intermediate"),
      q("mt2-35",ip,"clinical_judgment","A patient on a left ventricular assist device needs CPR.","How does CPR differ for a patient with an LVAD?","Standard CPR may not be appropriate for LVAD patients as the device provides continuous flow without pulsatile perfusion. I would first check the LVAD controller and connections, ensure power supply, listen for the device hum, and follow the institution's LVAD emergency protocol. External chest compressions may damage the device. The LVAD coordinator should be contacted immediately.","LVAD-specific resuscitation considerations.","advanced"),
      q("mt2-36",ct,"critical_thinking_drills","A patient's lactic acid is 8 mmol/L despite 2 hours of fluid resuscitation.","What does persistent lactic acidosis despite resuscitation indicate?","Persistent lactic acidosis despite adequate fluids suggests ongoing tissue hypoperfusion, mesenteric ischemia, uncontrolled septic source, or mitochondrial dysfunction. I would reassess fluid adequacy, add vasopressors if MAP is below 65, search for uncontrolled infection sources, check for bowel ischemia, and escalate care. Failure to clear lactate is associated with significantly increased mortality.","Persistent lactate elevation as treatment failure indicator.","advanced"),
      q("mt2-37",ip,"clinical_judgment","A patient develops posterior reversible encephalopathy syndrome.","How would you recognize PRES?","PRES presents with headache, seizures, visual disturbances, and altered mental status, often associated with severe hypertension, eclampsia, or immunosuppressive therapy. MRI shows characteristic posterior cerebral edema. Management includes aggressive blood pressure control, seizure management, and removal of the causative agent. Most cases are reversible with prompt treatment.","PRES recognition and management.","advanced"),
      q("mt2-38",ct,"critical_thinking_drills","A patient's cardiac enzymes show: Troponin 0.8, CK-MB 45.","Interpret these cardiac markers.","Troponin of 0.8 (normal <0.04) and elevated CK-MB indicate myocardial injury. The troponin elevation confirms cardiac muscle damage. I would correlate with ECG findings, assess chest pain characteristics, and determine if this represents an acute MI requiring emergent intervention or demand ischemia from another condition. Serial troponins showing a rise-and-fall pattern suggest acute MI.","Cardiac biomarker interpretation.","intermediate"),
      q("mt2-39",ip,"clinical_judgment","A patient on ECMO develops acute hemolysis.","What causes hemolysis on ECMO and how is it managed?","ECMO hemolysis results from mechanical shear stress on red blood cells through the pump and oxygenator. Signs include pink/red plasma, elevated LDH, decreased haptoglobin, and elevated free hemoglobin. Management includes reducing pump speed if tolerated, checking for circuit clots, ensuring proper cannula position, and managing anemia with transfusion. Severe hemolysis may require circuit change.","ECMO hemolysis recognition and management.","advanced"),
      q("mt2-40",ip,"clinical_judgment","A patient in septic shock achieves target MAP with fluids and vasopressors but remains oliguric.","What does persistent oliguria despite hemodynamic optimization suggest?","Persistent oliguria despite adequate MAP may indicate intrinsic renal injury from sepsis-related tubular damage rather than simply prerenal hypoperfusion. I would check urine sediment, fractional excretion of sodium, and renal biomarkers. I would avoid nephrotoxic medications, ensure adequate perfusion pressure, and anticipate possible renal replacement therapy. Recovery may take days to weeks.","Sepsis-related acute tubular necrosis versus prerenal failure.","advanced"),
      q("mt2-41",ct,"critical_thinking_drills","A patient's base excess is -10.","What does a negative base excess indicate?","Base excess of -10 (normal -2 to +2) indicates significant metabolic acidosis—the body has used up its buffer reserves. This is seen in shock, sepsis, DKA, and massive hemorrhage. In trauma, a base deficit greater than -6 is associated with significant blood loss. I would assess for the underlying cause and anticipate aggressive resuscitation. Serial base excess monitoring tracks treatment response.","Base excess as metabolic acidosis and resuscitation marker.","advanced"),
      q("mt2-42",ip,"clinical_judgment","A patient develops transfusion-associated circulatory overload.","How would you differentiate TACO from TRALI?","Both cause respiratory distress during/after transfusion, but TACO shows signs of fluid overload (elevated BNP, JVD, S3 gallop, positive fluid balance) and responds to diuretics, while TRALI shows bilateral infiltrates without fluid overload and does NOT respond to diuretics. TACO is more common. I would check BNP, chest X-ray, and fluid balance to differentiate.","TACO versus TRALI differentiation.","advanced"),
      q("mt2-43",ct,"critical_thinking_drills","A patient's serum lithium level is 2.5 mEq/L.","What does a toxic lithium level require?","Lithium of 2.5 (therapeutic 0.6-1.2) is severely toxic. Symptoms include coarse tremor, vomiting, diarrhea, confusion, seizures, and cardiac arrhythmias. I would hold lithium, ensure aggressive IV hydration with NS, place on cardiac monitoring, check renal function, and anticipate hemodialysis for levels above 2.5 or severe symptoms. Avoid diuretics as they can worsen toxicity.","Lithium toxicity with dialysis consideration.","advanced"),
      q("mt2-44",ip,"clinical_judgment","A patient with a subdural hematoma shows a fixed dilated pupil on the affected side.","What does ipsilateral pupil dilation indicate?","A fixed dilated pupil on the same side as a subdural hematoma indicates uncal herniation—the temporal lobe is herniating through the tentorial notch, compressing the third cranial nerve. This is a neurosurgical emergency requiring emergent craniotomy. I would administer mannitol or hypertonic saline, hyperventilate briefly to reduce ICP, and notify the neurosurgeon for immediate surgical evacuation.","Uncal herniation recognition as neurosurgical emergency.","advanced"),
      q("mt2-45",ct,"critical_thinking_drills","A patient's D-dimer is 5000 ng/mL.","When is a D-dimer clinically useful versus misleading?","D-dimer is useful for ruling OUT VTE when negative (high sensitivity, low specificity). A positive D-dimer of 5000 does NOT confirm VTE—it is elevated in many conditions: sepsis, malignancy, surgery, pregnancy, liver disease. The clinical utility is in its negative predictive value. For this patient, I would correlate with clinical probability scores (Wells criteria) and proceed to definitive imaging if VTE is suspected.","D-dimer interpretation limitations.","advanced"),
      q("mt2-46",ip,"clinical_judgment","A patient on prone positioning develops facial and airway edema.","How would you manage prone positioning complications?","Facial and airway edema are expected during prolonged proning from dependent fluid accumulation. I would monitor the endotracheal tube cuff pressure (edema can displace the tube), check ETT positioning, perform regular oral care carefully, protect pressure points, and prepare for potential difficult reintubation if the tube is displaced. Supination typically resolves the edema within hours.","Prone positioning complication management.","advanced"),
      q("mt2-47",ct,"critical_thinking_drills","A post-operative patient's hemoglobin drops from 12 to 7 in 6 hours without visible bleeding.","What does an unexplained hemoglobin drop suggest?","An unexplained hemoglobin drop of 5 g/dL in 6 hours without visible bleeding suggests internal hemorrhage—retroperitoneal bleed, surgical site bleeding into a body cavity, or hemolysis. I would assess for abdominal distension, flank ecchymosis, tachycardia, and hypotension. I would order a stat type and crossmatch, notify the surgeon, and anticipate CT imaging to locate the bleeding source.","Occult hemorrhage recognition with surgical awareness.","advanced"),
      q("mt2-48",ip,"clinical_judgment","A patient on continuous EEG monitoring develops non-convulsive status epilepticus.","How would you recognize and manage non-convulsive SE?","Non-convulsive SE may present subtly: altered consciousness, confusion, or eye deviation without obvious seizure activity. Continuous EEG confirms the diagnosis. Treatment is the same as convulsive SE: benzodiazepines followed by antiepileptic loading. Non-convulsive SE is more dangerous because it is often unrecognized, leading to prolonged untreated seizure activity and brain injury.","Non-convulsive SE recognition and management.","advanced"),
      q("mt2-49",ct,"critical_thinking_drills","A patient's arterial line shows dampened waveform.","What causes arterial line dampening?","Dampened arterial waveform can result from: air bubbles in the tubing, clot at the catheter tip, kinking of the catheter or tubing, inadequate flush solution, or vasospasm. I would fast-flush the line, check all connections, aspirate for clots, ensure the pressure bag is at 300 mmHg, and reposition the extremity. If dampening persists, I would obtain a cuff blood pressure and consider arterial line replacement.","Arterial line troubleshooting for dampened waveform.","advanced"),
      q("mt2-50",ip,"clinical_judgment","A patient develops posterior circulation stroke with locked-in syndrome.","How would you care for a patient with locked-in syndrome?","Locked-in syndrome from basilar artery stroke preserves consciousness but causes quadriplegia and anarthria—the patient is aware but cannot move or speak except for vertical eye movements. I would establish communication through eye blinks, ensure the team understands the patient is fully conscious, provide emotional support, prevent all immobility complications, and advocate for the patient's awareness in all care decisions.","Locked-in syndrome awareness and advocacy.","advanced"),
    ]
  },
  {
    id: "mock-workplace-safety-3",
    title: "Workplace Safety & Team Dynamics Assessment",
    description: "Test your ability to manage workplace challenges including patient safety, medication errors, team conflicts, and delegation scenarios.",
    category: "workplace_scenarios",
    difficulty: "intermediate",
    timeLimit: 55,
    supportsRandomization: true,
    questions: [
      q("mt3-1",ws,"prioritization","You receive report on 5 patients with varying acuity levels.","How would you organize your first hour?","I would identify the highest-risk patient and assess them first. I would do brief safety rounds on all patients within 15 minutes, then begin systematic detailed assessments by acuity. I would identify time-critical tasks (scheduled medications, procedures) and create a timeline for the shift.","First-hour organization strategy.","beginner"),
      q("mt3-2",ws,"prioritization","A code blue is called while you are in the middle of a procedure.","How would you handle a code blue during another task?","I would safely pause or stop my current procedure, secure the patient, and respond to the code blue. Codes take priority over almost everything else. I would ensure my current patient is safe before leaving and ask a colleague to monitor them if needed.","Code blue priority response.","beginner"),
      q("mt3-3",ws,"delegation","A new CNA does not understand the importance of accurate I&O measurement.","How would you educate about I&O importance?","I would explain the clinical significance: 'Accurate intake and output measurements help us determine if the patient's kidneys are working, if they are retaining fluid, or if they need more fluids. An error of even 100 mL can change treatment decisions. Let me show you the correct measurement technique.'","Clinical significance education for delegated tasks.","beginner"),
      q("mt3-4",ws,"patient_safety","A patient's sequential compression devices are not functioning.","How would you address non-functioning SCDs?","I would troubleshoot: check power, connections, and tubing. If the device is malfunctioning, I would replace it immediately. SCDs prevent DVT in immobile patients, and interruptions increase clot risk. I would document the duration of interruption and ensure the replacement is functioning properly.","DVT prevention equipment troubleshooting.","beginner"),
      q("mt3-5",ws,"medication_error","A pharmacy sends a medication with a different concentration than what was ordered.","How would you handle a pharmacy concentration discrepancy?","I would not administer the medication. I would call pharmacy to verify whether they substituted the concentration and if the dose volume needs adjustment. I would calculate the correct volume for the ordered dose at the new concentration and verify with another nurse. Concentration discrepancies are a leading cause of dosing errors.","Concentration discrepancy verification.","intermediate"),
      q("mt3-6",ws,"handoff_communication","You need to transfer a patient to the ICU.","What information is critical for a floor-to-ICU transfer?","I would provide: reason for ICU transfer, current hemodynamic status and trends, active interventions and drip rates, most recent labs and imaging, code status, pertinent medical history, current medications, IV access details, family contact information, and what has and has not worked during the acute change.","Comprehensive ICU transfer communication.","intermediate"),
      q("mt3-7",ws,"difficult_coworkers","A night shift nurse consistently leaves tasks undone for the day shift.","How would you address incomplete task handoff?","I would document the pattern, discuss it with the night shift nurse directly first: 'I have noticed that wound care assessments are frequently incomplete at shift change. Can we discuss expectations so patients receive consistent care across shifts?' If no improvement, I would escalate to the charge nurse with documented examples.","Pattern documentation with direct communication.","intermediate"),
      q("mt3-8",ws,"interdisciplinary_communication","Pharmacy questions your clarification request on a medication order.","How would you maintain your medication safety concern?","I would stand firm: 'I appreciate your expertise. However, I have a specific clinical concern about this order for this particular patient because of [clinical reason]. I would like the prescriber to review and confirm. Patient safety requires us both to be comfortable with the medication plan.'","Assertive medication safety advocacy.","intermediate"),
      q("mt3-9",ws,"prioritization","Three patients need pain medication simultaneously.","How do you determine which patient gets medication first?","I would assess severity: the patient with the highest pain level and most acute condition gets treated first. If pain levels are equal, I would consider the patient who has been waiting longest and whether any medications are time-critical (e.g., pre-procedure). I would communicate realistic timelines to all three patients.","Pain management prioritization with communication.","beginner"),
      q("mt3-10",ws,"patient_safety","A confused patient is climbing over the side rails.","How do you manage a confused patient attempting to leave bed?","I would assist them safely and determine their need: toileting, pain, hunger, or disorientation. I would address the underlying cause, activate the bed alarm, lower the bed to the lowest position, consider padding side rails, ensure a safe environment, and contact the provider about possible pharmacological intervention if agitation is severe.","Need-based intervention for confused patients.","beginner"),
      q("mt3-11",ws,"delegation","You need help but the only available staff is a float nurse from a different specialty.","How would you utilize a float nurse from an unfamiliar specialty?","I would orient them briefly to unit-specific needs, assign patients within their competency, provide extra support for unfamiliar aspects, and be available for questions. I would not assign the most complex patients to the float nurse. I would check in more frequently than with a unit-regular nurse.","Safe float nurse utilization.","intermediate"),
      q("mt3-12",ws,"medication_error","A patient with renal failure is prescribed a full-dose medication that requires renal adjustment.","How would you address a non-adjusted medication in renal failure?","I would hold the medication and contact the prescriber: 'This patient's GFR is 25. The prescribed dose of this medication requires renal adjustment per the pharmacy reference. Can we review the dosing?' I would also consult with pharmacy. Renal dose adjustment is one of the most commonly missed safety checks.","Renal dosing verification advocacy.","intermediate"),
      q("mt3-13",ws,"handoff_communication","You receive report on a patient and realize the outgoing nurse omitted critical information.","How would you handle incomplete handoff information?","I would call the outgoing nurse immediately for clarification rather than trying to figure it out independently. 'I noticed the new lab result from this morning was not mentioned in report. Can you update me on the significance and any related orders?' Proactive clarification prevents care gaps.","Immediate handoff gap clarification.","beginner"),
      q("mt3-14",ws,"difficult_coworkers","A colleague makes a sarcastic comment about your clinical decision.","How would you respond to sarcasm about your clinical judgment?","I would address it calmly: 'I sense you disagree with my clinical decision. I would value your perspective if you share it constructively. Can you explain what you would do differently?' Converting sarcasm into constructive dialogue demonstrates maturity and may reveal a valid alternative approach.","Sarcasm redirection to constructive dialogue.","intermediate"),
      q("mt3-15",ws,"patient_safety","A patient's bed alarm is alarming continuously due to restlessness.","How would you manage continuous bed alarm activation?","I would assess why the patient is restless—pain, anxiety, need for toileting, medication effects. I would address the root cause. I would not disable the alarm for a high-fall-risk patient. I would adjust sensitivity, consider alternative monitoring, and evaluate whether a sitter is needed. Alarm fatigue from constant alarming is a real safety risk.","Root cause approach to continuous alarms.","intermediate"),
      q("mt3-16",ws,"interdisciplinary_communication","The physician writes an order you believe is incomplete.","How would you address an incomplete physician order?","I would contact the physician for clarification: 'I received your order for metoprolol but the dose, route, and frequency are not specified. Can you complete the order so I can administer it safely?' I would not guess or fill in missing order elements independently. Complete orders are a patient safety requirement.","Incomplete order clarification.","beginner"),
      q("mt3-17",ws,"medication_error","You witness another nurse scanning a medication but not actually administering it.","How would you address documentation without administration?","I would approach privately: 'I noticed you scanned the medication for room 308 but I did not see you administer it. Did the patient refuse or was there a reason it was not given?' If the documentation was falsified, I would report it as a patient safety concern and medication error.","Observation-based documentation integrity.","intermediate"),
      q("mt3-18",ws,"delegation","A nursing student asks to perform a task beyond their current competency level.","How would you manage an overly ambitious nursing student?","I would appreciate their enthusiasm while maintaining safety: 'I love your eagerness to learn. That skill requires additional training and is beyond what your clinical instructor has authorized today. Let me demonstrate it while you observe, and you can discuss with your instructor about including it in your next competency evaluation.'","Supportive skill boundary management for students.","beginner"),
      q("mt3-19",ws,"patient_safety","Two patients on your unit have the same last name.","How would you prevent identity-related errors with same-named patients?","I would use two patient identifiers for every interaction, ensure wristbands are correct, communicate the risk during handoff, avoid using room numbers as identifiers, and be extra vigilant during medication administration. I would alert all team members about the same-name situation. Same-name patients are a well-known risk factor for identification errors.","Same-name patient safety precautions.","beginner"),
      q("mt3-20",ws,"handoff_communication","Your shift was chaotic and you need to give a coherent report.","How would you organize report after a chaotic shift?","I would take 5 minutes before handoff to organize my thoughts using SBAR for each patient. I would focus on what changed during my shift, current status, and what the next nurse needs to know. I would be honest about anything incomplete: 'I was not able to complete the 1600 skin assessment due to the emergency—this needs follow-up.'","Post-chaos report organization.","beginner"),
      q("mt3-21",ws,"prioritization","A rapid response is called on your patient while you are on your lunch break.","How would you handle a rapid response during your break?","I would return immediately—my patient's emergency supersedes my break. The rapid response team provides initial support, but as the primary nurse I have essential patient knowledge. I would provide pertinent history, current medications, and what I observed before my break. I would take my break after the patient is stabilized.","Break interruption for patient emergency.","beginner"),
      q("mt3-22",ws,"medication_error","A patient asks about a medication interaction with their herbal supplements.","How would you address herbal-drug interaction concerns?","I would take the concern seriously, check interaction databases, consult with pharmacy, and communicate findings to the provider. Many herbal supplements interact with medications: St. John's Wort with SSRIs, ginkgo with anticoagulants, and garlic with blood thinners. I would document all supplements in the medication reconciliation.","Herbal supplement interaction assessment.","intermediate"),
      q("mt3-23",ws,"difficult_coworkers","A colleague is consistently on their phone during patient care.","How would you address phone distractions during patient care?","I would address it if patient care is affected: 'I have noticed phone use during medication passes, which concerns me because distractions increase error risk. I want us all to be safe. Would you consider putting your phone away during high-focus tasks?' If it continued, I would document and discuss with the charge nurse.","Distraction-based patient safety concern.","beginner"),
      q("mt3-24",ws,"interdisciplinary_communication","A physical therapist reports that a patient is unsafe to discharge home alone.","How would you act on a PT safety concern about discharge?","I would document the PT's findings, communicate the safety concern to the physician and case manager, advocate for a team meeting to discuss discharge planning, and ensure the concern is addressed before the patient leaves. I would not discharge a patient that multiple disciplines believe is unsafe.","Interdisciplinary discharge safety advocacy.","intermediate"),
      q("mt3-25",ws,"patient_safety","A patient's blood product is due but the second nurse for verification is unavailable.","How would you manage blood product verification requirements?","I would not administer the blood product until two-nurse verification is completed—this is a non-negotiable safety requirement. I would search for another RN on the unit, contact the charge nurse, or call the house supervisor. Blood product verification cannot be skipped regardless of urgency, as transfusion errors can be fatal.","Non-negotiable blood product verification.","intermediate"),
      q("mt3-26",ws,"delegation","A CNA reports unusual patient behavior but cannot articulate specific concerns.","How would you respond to a vague CNA observation?","I would assess the patient immediately. CNAs spend significant time with patients and often detect subtle changes before they can articulate specific findings. I would ask targeted questions: 'Is the patient acting differently from earlier? What specifically seems different?' I would perform my own assessment and compare to baseline.","Investigating vague but important CNA observations.","beginner"),
      q("mt3-27",ws,"medication_error","A patient is prescribed a medication they took before with poor results.","How would you handle a historically ineffective medication?","I would verify the patient's report, check their medication history, and communicate to the prescriber: 'The patient reports they previously took this medication without benefit. Their chart confirms it was discontinued for lack of efficacy. Could we discuss alternative options?' Patient history with a medication is valuable prescribing information.","Patient-reported medication history advocacy.","beginner"),
      q("mt3-28",ws,"handoff_communication","You need to communicate a complex patient situation during a brief hallway encounter.","How would you give an effective brief update?","I would focus on the most critical information: 'Quick update on 305: Blood pressure dropped to 82/50, I gave a 500 mL NS bolus, it is now 96/60 and trending up. The physician is aware and ordered repeat labs in 2 hours. Please keep an eye on the blood pressure while I check my other patients.'","Concise critical information communication.","beginner"),
      q("mt3-29",ws,"difficult_coworkers","A colleague regularly arrives late for their shift.","How would you manage chronic tardiness from a colleague?","I would address it if it directly affects patient care and my ability to leave on time: 'I understand things happen, but I have noticed a pattern of late arrivals that delays my shift change. Is there something going on? If this continues, it affects patient handoff safety.' If the pattern continued, I would document and escalate.","Direct tardiness discussion with documentation.","beginner"),
      q("mt3-30",ws,"patient_safety","A patient on suicide precautions needs to use the bathroom.","How would you maintain suicide precautions during bathroom use?","I would accompany the patient, ensure the bathroom is free of harmful items (sharps, cords, chemicals), keep the door slightly open or maintain line of sight, and stay close enough to intervene if needed. Suicide precaution patients should never be left unattended. I would document the safety measures and patient behavior.","Suicide precaution maintenance during activities.","intermediate"),
      q("mt3-31",ws,"prioritization","Two patients need emergent interventions but you are the only nurse available.","How do you manage two simultaneous emergencies alone?","I would call for help immediately, then rapidly assess which patient has the most immediately life-threatening condition. I would initiate interventions for the higher-priority patient while waiting for help. Once assistance arrives, I would direct them to the second patient. I would not try to manage both independently—calling for help IS the first intervention.","Dual emergency triage with immediate help activation.","intermediate"),
      q("mt3-32",ws,"medication_error","You discover a systematic error in the medication dispensing cabinet.","How would you report a systemic medication safety issue?","I would stop using the affected drawer, notify pharmacy immediately, check if any patients received incorrect medications, alert the charge nurse, and file a safety report. I would advocate for a system-wide check of similar dispensing cabinets. Systemic errors affect multiple patients and require rapid, comprehensive response.","Systemic safety error escalation.","intermediate"),
      q("mt3-33",ws,"interdisciplinary_communication","A dietitian and physician disagree about a patient's nutritional plan.","How would you navigate nutritional plan disagreements?","I would document both perspectives, share my nursing assessment of the patient's nutritional status and preferences, and facilitate communication between the two professionals. I would advocate for the plan that best supports the patient's clinical needs and personal preferences. The patient's perspective should be central to any nutritional plan.","Patient-centered nutritional conflict mediation.","intermediate"),
      q("mt3-34",ws,"patient_safety","A visitor is not following infection control precautions.","How would you address visitor non-compliance with precautions?","I would approach politely: 'I notice you are not wearing the required mask. These precautions protect your loved one from infection. Let me help you put on the proper equipment.' I would explain the clinical rationale. If the visitor refuses after education, I would involve the charge nurse and enforce the policy.","Educational approach to visitor precaution compliance.","beginner"),
      q("mt3-35",ws,"delegation","You need to delegate turning and repositioning but want to ensure skin assessment.","How would you delegate repositioning with skin assessment integration?","I would instruct: 'When you reposition Mrs. Park, please check her skin on her sacrum, heels, and elbows. Let me know if you see any redness that does not blanch when you press on it, any open areas, or any changes from earlier. Also document the position change on the turn clock.'","Combined delegation with assessment integration.","beginner"),
      q("mt3-36",ws,"medication_error","A patient's PRN medication request frequency raises concern for dependency.","How would you manage increasing PRN medication requests?","I would assess pain objectively each time, document the request pattern, evaluate the effectiveness of current pain management, and communicate the trend to the provider: 'The patient has requested PRN oxycodone 8 times in 24 hours. Their pain remains at 7/10 despite scheduled medication. Can we discuss a more effective pain management approach?' I would not judge or withhold prescribed medication.","Objective PRN pattern communication without judgment.","intermediate"),
      q("mt3-37",ws,"handoff_communication","You need to give report to the charge nurse about a patient going bad.","How would you communicate clinical deterioration urgently?","I would be direct and specific: 'I need you at bedside now. Mr. Thompson in 308 is deteriorating: BP dropped from 130 to 85, heart rate increased from 80 to 120, and he is becoming confused. I have started a fluid bolus and called the physician. I think he may need a rapid response.' Urgency requires clear, concise communication.","Urgent deterioration communication.","intermediate"),
      q("mt3-38",ws,"patient_safety","A patient is found to have a medication allergy not documented in their chart.","How would you manage an undocumented allergy discovery?","I would immediately update the allergy section in the medical record, apply an allergy wristband, verify the reaction type and severity, check all current medications for cross-reactivity, notify the physician, and alert pharmacy. I would educate the patient about the importance of reporting allergies at every healthcare encounter.","Undocumented allergy discovery and system update.","beginner"),
      q("mt3-39",ws,"difficult_coworkers","A colleague questions your competence in front of a patient.","How would you handle public competence questioning?","I would remain calm and redirect: 'I appreciate your concern. Let us step outside to discuss this so we can focus on providing the best care for our patient.' In private, I would address the behavior directly and assertively. Questioning competence in front of patients undermines trust and is unprofessional.","Private redirection of public competence questioning.","intermediate"),
      q("mt3-40",ws,"interdisciplinary_communication","You need to advocate for a patient during interdisciplinary rounds.","How would you present your nursing perspective during rounds?","I would prepare by reviewing the patient's current status, trends, and my assessment findings. I would present: 'From the nursing perspective, the patient's [specific finding] is concerning because [clinical reasoning]. I recommend [specific action]. The patient has also expressed [patient preference or concern].' Nursing adds the 24/7 perspective that other disciplines may not see.","Prepared nursing perspective for interdisciplinary rounds.","intermediate"),
    ]
  },
  {
    id: "mock-new-grad-transition-4",
    title: "New Graduate Transition Readiness Assessment",
    description: "Comprehensive assessment of readiness for independent nursing practice covering clinical transition, professional development, and career planning.",
    category: "clinical_transition",
    difficulty: "beginner",
    timeLimit: 50,
    supportsRandomization: true,
    questions: [
      q("mt4-1",ct,"first_shift","You arrive for your first day on the unit.","What are your priorities for the first day?","I would arrive early, introduce myself to the charge nurse and my preceptor, review the unit layout and emergency equipment locations, familiarize myself with the documentation system, review my assigned patients' charts, and set realistic expectations for the day. I would express my eagerness to learn and my openness to feedback.","First day preparation and priorities.","beginner"),
      q("mt4-2",ct,"new_nurse_anxiety","You feel like you don't know enough to be a nurse.","How would you manage imposter syndrome as a new graduate?","I would remind myself that imposter syndrome is extremely common among new professionals and does not reflect my actual competence. I passed the NCLEX—I am qualified. I would focus on daily improvements, seek feedback, and keep a journal of what I learned each shift. I would connect with other new graduates who share similar feelings.","Imposter syndrome management.","beginner"),
      q("mt4-3",ct,"time_management","Your morning is consistently behind schedule.","What strategies would you implement for better time management?","I would create a structured brain sheet, plan my workflow the night before, arrive 15 minutes early to review charts, cluster care activities, set personal time deadlines for tasks, and delegate appropriately. I would study the workflow of efficient experienced nurses and adopt their strategies.","Comprehensive time management strategies.","beginner"),
      q("mt4-4",ct,"documentation_challenges","You are uncertain about what level of detail to include in documentation.","How do you determine appropriate documentation detail?","I would document: significant assessment findings (both normal and abnormal for the patient's condition), interventions performed, patient responses, provider communications, and patient education. I would be specific about abnormal findings and use measurable descriptions. I would not document opinions or speculation. When in doubt, more detail is better than less.","Documentation detail decision framework.","beginner"),
      q("mt4-5",ct,"critical_thinking_drills","You notice a subtle change in your patient that you cannot fully articulate.","How would you address a clinical gut feeling?","I would take my gut feeling seriously—clinical intuition is often subconscious pattern recognition. I would perform a thorough assessment looking for objective findings that might explain my concern. I would communicate: 'Something seems different about this patient. Let me perform a focused assessment and report back.' I would not dismiss my instincts.","Trusting and investigating clinical intuition.","intermediate"),
      q("mt4-6",pd,"professional_boundaries","A patient gives you expensive gifts after discharge.","How would you handle post-discharge gifts?","I would follow facility policy. Most policies prohibit accepting expensive personal gifts. I would redirect: 'I am so touched. While I cannot accept personal gifts, our hospital foundation accepts donations that support patient care programs. Your gratitude means the world to me.'","Post-discharge gift policy adherence.","beginner"),
      q("mt4-7",pd,"ethical_dilemmas","You disagree with a treatment plan you believe is futile.","How would you manage feelings about futile treatment?","I would express my concerns through proper channels: discuss with the charge nurse, request an ethics committee consultation, and participate in goals-of-care conversations. I would continue providing competent care while advocating for the patient's best interest. I would process my moral distress through debriefing and support resources.","Moral distress management with proper advocacy channels.","intermediate"),
      q("mt4-8",pd,"advocacy","A patient does not understand their rights as a patient.","How would you educate patients about their rights?","I would ensure patients receive the Patient Bill of Rights upon admission, explain their rights in plain language, emphasize their right to refuse treatment, ask questions, request a second opinion, and access their medical records. I would serve as their advocate when they feel their rights are not being respected.","Patient rights education.","beginner"),
      q("mt4-9",pd,"patient_communication","A patient breaks down crying during your assessment.","How would you respond to unexpected patient tears?","I would pause the assessment, offer tissues, sit down to be at their level, and say something simple: 'It is okay to cry. Take your time.' I would not rush to fill the silence or immediately try to fix the problem. Sometimes patients need someone to simply be present with their pain.","Therapeutic presence during emotional moments.","beginner"),
      q("mt4-10",cn,"job_offer_negotiation","You are asked 'Why should we hire you?'","How would you sell yourself to a potential employer?","I would focus on what makes me unique: 'I bring a combination of strong clinical training, genuine passion for patient care, and the determination to continuously improve. My CNA experience gave me practical skills and patient relationship abilities that many new graduates lack. I am committed to this unit long-term and to becoming a valuable team member.'","Compelling self-advocacy with unique differentiators.","beginner"),
      q("mt4-11",ct,"first_shift","Your preceptor has a different approach than what you learned in school.","How would you handle practice differences from education?","I would ask about the reasoning: 'I learned a different technique in school. Can you explain why you approach it this way?' I would keep an open mind—clinical practice often differs from textbook approaches for valid reasons. If the difference involves a safety concern, I would check the facility policy as the definitive reference.","Open-minded practice difference exploration.","beginner"),
      q("mt4-12",ct,"new_nurse_anxiety","You dread going to work because of a difficult colleague.","How would you manage workplace dread from interpersonal conflict?","I would separate the interpersonal issue from my professional commitment. I would address the conflict directly if safe, involve the charge nurse or manager if needed, and focus on what I can control—my own professionalism and patient care. If the situation does not improve, I would document and escalate through proper channels.","Interpersonal conflict management.","beginner"),
      q("mt4-13",ct,"time_management","You are responsible for multiple discharges on the same day.","How would you manage multiple discharges efficiently?","I would identify the earliest expected discharge time for each patient, prepare discharge education materials in advance, stagger discharge teaching sessions, involve case management for complex discharges, delegate paperwork preparation to support staff, and ensure each patient has follow-up appointments before leaving.","Multiple discharge management efficiency.","beginner"),
      q("mt4-14",ct,"documentation_challenges","You need to chart during a busy shift without falling behind.","What strategies help maintain real-time documentation?","I would chart at the bedside using a mobile workstation, document assessment findings immediately during the assessment, use the system's templates and quick-entry features, chart by exception for normal findings, and prioritize documenting clinical changes and interventions. I would set a goal of completing each patient's documentation before moving to the next patient.","Real-time documentation strategies.","beginner"),
      q("mt4-15",ct,"critical_thinking_drills","A patient's morning labs show multiple abnormal values.","How do you prioritize and act on multiple abnormal labs?","I would identify life-threatening values first (critical potassium, critical glucose), then values requiring urgent attention (significantly abnormal renal or liver function), then values requiring monitoring (slightly out of range). I would notify the provider about all abnormal values, prioritizing the most clinically significant, and implement any standing protocol interventions.","Multiple abnormal lab prioritization framework.","beginner"),
      q("mt4-16",pd,"professional_boundaries","You feel emotionally attached to a patient's family.","How would you maintain boundaries with a patient's family?","I would recognize the attachment, maintain professional behavior, limit personal sharing, and seek peer support. I would channel my empathy into excellent clinical care. If the attachment is affecting my objectivity or professional judgment, I would discuss it with my charge nurse and consider whether reassignment would benefit both me and the family.","Emotional attachment self-awareness and management.","beginner"),
      q("mt4-17",pd,"ethical_dilemmas","A patient asks you to pray with them.","How would you handle a patient's spiritual request?","I would respond with genuine compassion. If comfortable, I could sit quietly with them while they pray. If the request is beyond my comfort level, I would say: 'I want to support your spiritual needs. Let me contact our chaplain who specializes in spiritual care.' I would respect their spiritual practice regardless of my own beliefs.","Supportive response to spiritual requests.","beginner"),
      q("mt4-18",pd,"advocacy","A patient is being treated dismissively by a healthcare provider.","How would you advocate for a patient being dismissed?","I would speak up: 'I would like to ensure we have fully heard Mrs. Garcia's concerns before proceeding.' I would validate the patient's experience, ensure their questions are answered, and report dismissive behavior if it represents a pattern. Every patient deserves to be heard and treated with respect.","Patient dignity advocacy against dismissive behavior.","intermediate"),
      q("mt4-19",cn,"career_advancement","You want to set meaningful professional goals.","How would you create a professional development plan?","I would assess my current strengths and gaps, identify short-term goals (certifications, skills), medium-term goals (specialty expertise, committee leadership), and long-term aspirations (advanced practice, education, administration). I would create SMART goals with timelines, seek mentorship, and review progress quarterly.","Structured professional development planning.","beginner"),
      q("mt4-20",cn,"probation_period","You are approaching the end of probation and want to demonstrate your value.","How would you showcase your contributions during probation?","I would prepare a summary of: competencies achieved, patient safety catches, positive feedback received, committee participation, continuing education completed, and quality improvement contributions. I would present this at my evaluation along with specific goals for the next period, demonstrating both accomplishment and forward-thinking commitment.","Probation contribution documentation and presentation.","beginner"),
      q("mt4-21",ct,"first_shift","Your patient assignment changes unexpectedly mid-shift.","How would you manage an unexpected assignment change?","I would receive a thorough handoff from the current nurse, review the new patient's chart, perform a focused assessment, identify immediate needs, and reorganize my workflow. I would communicate the transition to the patient: 'I am your new nurse for the remainder of the shift. Let me catch up on your care and see how you are doing.'","Mid-shift assignment change management.","beginner"),
      q("mt4-22",ct,"time_management","You are expected to take a full patient load but feel unprepared.","How would you communicate readiness concerns?","I would have an honest conversation with my preceptor and manager: 'I want to be transparent about my comfort level. I feel confident with [specific skills] but am still developing [specific areas]. Can we discuss a graduated increase in my patient load to ensure patient safety while building my confidence?'","Honest readiness communication with graduated plan.","beginner"),
      q("mt4-23",pd,"patient_communication","A patient expresses hopelessness about their prognosis.","How would you respond to a patient expressing hopelessness?","I would validate their feelings without dismissing them: 'It makes sense to feel that way given what you are going through. I want you to know that you are not alone in this—we are here to support you.' I would screen for depression, ensure appropriate referrals, and communicate the patient's emotional state to the care team.","Validating hopelessness without dismissing or false reassurance.","intermediate"),
      q("mt4-24",cn,"career_advancement","You are considering whether to stay on your current unit or transfer.","How would you evaluate a unit transfer decision?","I would consider: Have I given adequate time to develop competence (minimum 12-18 months)? Is my desire to leave based on temporary frustration or genuine misalignment? What growth opportunities remain? Would a transfer advance my career goals? I would discuss with my mentor and manager before making a decision.","Thoughtful unit transfer evaluation.","beginner"),
      q("mt4-25",ct,"critical_thinking_drills","A patient with no cardiac history has a new irregularly irregular heart rhythm.","What does a new irregular rhythm suggest?","An irregularly irregular rhythm is characteristic of atrial fibrillation. Even without cardiac history, new-onset AFib can occur with sepsis, surgery, thyroid dysfunction, alcohol use, or pulmonary embolism. I would verify with a 12-lead ECG, assess heart rate and hemodynamic stability, notify the provider, and prepare for possible rate control and anticoagulation.","New atrial fibrillation assessment with trigger identification.","intermediate"),
      q("mt4-26",pd,"workplace_bullying","You feel isolated and unsupported on your unit.","How would you build a support network when feeling isolated?","I would actively seek connections: identify approachable colleagues, join the new graduate residency cohort, participate in unit social activities, seek a formal mentor, and maintain relationships with nursing school classmates. I would also use EAP services if isolation is affecting my mental health. Professional isolation is a retention risk that requires proactive intervention.","Active support network building.","beginner"),
      q("mt4-27",ct,"documentation_challenges","You need to document a patient's non-compliance with treatment.","How would you document treatment non-adherence?","I would use objective, non-judgmental language: 'Patient chose not to take prescribed metformin today. Education provided regarding importance of glycemic control and risks of non-adherence. Patient verbalized understanding of risks and stated personal choice to decline. Physician notified.' I would avoid the word 'non-compliant' which is stigmatizing—use 'chose not to' or 'declined.'","Non-judgmental non-adherence documentation.","beginner"),
      q("mt4-28",cn,"performance_evaluation","Your evaluation identifies areas needing improvement.","How would you create an action plan from evaluation feedback?","I would create specific improvement goals with timelines: 'Based on feedback about time management, I will implement a structured brain sheet within 1 week, observe two experienced nurses' workflows within 2 weeks, and demonstrate improved shift completion by 30 days. I will check in with my manager weekly to report progress.'","Actionable improvement plan with accountability.","beginner"),
      q("mt4-29",ct,"new_nurse_anxiety","Your confidence fluctuates from day to day.","How would you build consistent clinical confidence?","I would recognize that confidence fluctuation is normal during the first year. I would track my clinical decisions and outcomes in a journal, noting that most of my decisions are correct. I would celebrate my wins, learn from challenging situations without catastrophizing, and seek specific positive feedback from my preceptor. Confidence grows from accumulated evidence of competence.","Evidence-based confidence building.","beginner"),
      q("mt4-30",pd,"advocacy","A patient is about to be discharged but their home environment is unsafe.","How would you prevent an unsafe discharge?","I would document my safety concerns specifically, communicate them to the physician and case manager, request a multidisciplinary team meeting, advocate for home health evaluation, and ensure community resources are arranged before discharge. I would escalate if necessary: 'I do not believe this discharge is safe because [specific reasons]. What alternatives can we explore?'","Unsafe discharge prevention advocacy.","intermediate"),
      q("mt4-31",ct,"first_shift","You witness a near-miss medication error by an experienced nurse.","How would you handle observing an experienced nurse's near-miss?","I would address it supportively: 'I noticed the medication labels did not match—I think we caught it in time. Would you like me to help verify the correct medication?' I would encourage reporting through the safety system and model a non-punitive safety culture. Near-misses are learning opportunities for the entire team.","Supportive near-miss intervention with safety reporting.","beginner"),
      q("mt4-32",cn,"career_advancement","You are interested in pursuing nursing research.","How would you explore nursing research opportunities?","I would attend journal clubs, volunteer for research studies on my unit, take a research methods course, identify a research question related to my clinical practice, and seek mentorship from a nurse researcher. Research starts with asking questions about why we do what we do and whether there might be better approaches.","Clinical research exploration.","intermediate"),
      q("mt4-33",ct,"time_management","You consistently struggle with end-of-shift documentation.","How would you prevent end-of-shift documentation backlog?","I would commit to point-of-care charting, set phone alarms for documentation checkpoints throughout the shift, develop a personal documentation template that speeds entry, and identify which documentation components take the most time so I can streamline them. I would avoid the trap of batching all charting until the end of the shift.","Documentation backlog prevention strategies.","beginner"),
      q("mt4-34",pd,"professional_boundaries","A patient's family asks you to promise their loved one will be okay.","How would you handle a family requesting reassurance you cannot give?","I would be honest and compassionate: 'I understand you want reassurance, and I wish I could promise everything will be fine. What I can promise is that we are doing everything possible to give your loved one the best possible care. The physician can discuss the medical outlook with you in more detail.'","Honest response to unrealistic reassurance requests.","beginner"),
      q("mt4-35",ct,"critical_thinking_drills","A patient who was stable suddenly becomes tachycardic and anxious.","What would cause sudden tachycardia and anxiety in a previously stable patient?","The combination suggests an acute change: possible PE, hemorrhage, sepsis onset, pain, anxiety, or medication reaction. I would assess comprehensively: vital signs, oxygen saturation, breath sounds, abdominal exam, recent medication administration, and mental status. I would not attribute it to anxiety alone without ruling out medical causes. SBAR communication to the provider is urgent.","Sudden tachycardia assessment with medical-first approach.","intermediate"),
      q("mt4-36",pd,"ethical_dilemmas","A patient in cognitive decline signs a consent form.","How would you assess capacity for informed consent?","I would assess: Can the patient understand the information being presented? Can they appreciate how it applies to their situation? Can they reason about the risks and benefits? Can they communicate a clear choice? Cognitive decline does not automatically eliminate capacity—it must be assessed specifically for the decision at hand. I would involve the physician and possibly ethics if capacity is questionable.","Decision-specific capacity assessment.","intermediate"),
      q("mt4-37",cn,"probation_period","You want to show initiative but are afraid of overstepping.","How would you demonstrate initiative appropriately during probation?","I would focus on areas that are clearly within my scope: organizing supplies, preparing for anticipated needs, offering to help colleagues, researching my patients' conditions, and suggesting improvements to my own workflow. For larger initiatives, I would ask permission first: 'I noticed an opportunity to improve X. Would it be appropriate for me to work on this?'","Scope-appropriate initiative demonstration.","beginner"),
      q("mt4-38",ct,"documentation_challenges","You receive conflicting information from the patient and their chart.","How would you reconcile patient report with chart information?","I would investigate further: 'I want to make sure your records are accurate. Your chart says you take lisinopril 10mg but you mentioned 20mg. When was the dose changed?' I would verify with the pharmacy, update the chart if needed, and document the reconciliation. Patient self-report is a valuable data source that should not be automatically overridden by the chart.","Chart-patient information reconciliation.","beginner"),
      q("mt4-39",pd,"patient_communication","A non-verbal patient needs pain assessment.","How would you assess pain in a non-communicative patient?","I would use a validated behavioral pain scale (FLACC, BPS, CPOT): assess facial expression, body movements, muscle tension, compliance with ventilator if applicable, and consolability. I would check vital signs for physiological indicators. I would trial pain medication and reassess. I would involve family members who know the patient's baseline behavior.","Behavioral pain assessment for non-verbal patients.","intermediate"),
      q("mt4-40",cn,"career_advancement","You are at a crossroads between two career paths.","How would you make a career direction decision?","I would evaluate both paths against my values, interests, lifestyle needs, and long-term goals. I would shadow nurses in both areas, seek advice from mentors, consider the job market, and give myself permission to change direction later. Nursing careers rarely follow a straight line—what matters is choosing a direction and committing to excellence in it.","Values-based career direction decision-making.","beginner"),
      q("mt4-41",ct,"first_shift","You feel like you are slowing down the team.","How would you manage feeling like a burden to the team?","I would remind myself that every experienced nurse was once new and needed time to develop. I would focus on being reliable, showing effort, and expressing gratitude for help. I would set personal improvement goals each week. Over time, I will become the experienced nurse who supports new team members. This stage is temporary.","Normalizing the new nurse learning curve.","beginner"),
      q("mt4-42",pd,"advocacy","A patient asks you to help them make a complaint about their care.","How would you assist a patient with a care complaint?","I would listen to their concern, validate their experience, and provide information about the complaint process: patient advocate contact, comment cards, and formal complaint procedures. I would not discourage them from complaining or defend the care they are questioning. Patients have the right to voice concerns and receive a response.","Patient complaint facilitation.","beginner"),
      q("mt4-43",ct,"new_nurse_anxiety","You compare yourself unfavorably to your nursing school peers.","How would you manage comparison anxiety?","I would recognize that comparison is natural but unproductive. Each new nurse has different strengths, challenges, and learning timelines. I would focus on my own growth trajectory rather than others' apparent success. I would celebrate my own progress and remember that social media and casual conversations often present a curated version of reality.","Comparison management with self-focus.","beginner"),
      q("mt4-44",cn,"probation_period","Your probation evaluation is approaching and you want to prepare.","How would you prepare for your probation evaluation?","I would gather evidence of my growth: competencies completed, positive feedback, challenging situations managed, CE completed, and goals achieved. I would self-evaluate using the evaluation criteria, identify areas for continued growth, and prepare specific questions about my performance. I would approach the evaluation as a collaborative conversation, not a judgment.","Comprehensive evaluation preparation.","beginner"),
      q("mt4-45",ct,"critical_thinking_drills","A patient's trending vital signs show a pattern of gradual decline.","How would you act on a gradual vital sign trend?","Gradual trends are often more significant than a single abnormal value because they indicate a developing clinical change. I would document the trend, compare each value to the patient's baseline, assess for clinical correlation, and notify the provider with the trend pattern rather than individual values. 'Over the past 8 hours, the blood pressure has dropped from 130 to 105 while the heart rate increased from 75 to 95.'","Trend-based clinical communication.","intermediate"),
      q("mt4-46",pd,"patient_communication","A patient asks about their prognosis and you do not have the authority to discuss it.","How would you redirect prognostic questions appropriately?","I would acknowledge the importance of the question: 'That is a crucial question and you deserve a thorough answer. Your physician is the best person to discuss prognosis because they have the complete picture. I will make sure your question is flagged for the next physician visit. In the meantime, is there anything I can help clarify about your current treatment?'","Prognostic question redirection with support.","beginner"),
      q("mt4-47",ct,"documentation_challenges","You are unsure about your nurse's note narrative.","How would you improve your narrative documentation?","I would follow a structured format: what I observed (objective data), what I assessed (clinical impression), what I did (interventions), patient response, and follow-up plan. I would review documentation examples from experienced nurses, use specific measurable language, and seek feedback from my preceptor on my documentation quality.","Narrative documentation skill development.","beginner"),
      q("mt4-48",cn,"career_advancement","You want to stay motivated during the challenging first year.","How would you maintain motivation during the difficult transition period?","I would keep a gratitude journal noting positive patient interactions, set small achievable weekly goals, celebrate each competency milestone, maintain connections with supportive colleagues, remember why I chose nursing, and take care of my physical and mental health. I would give myself permission to have bad days without questioning my career choice.","First-year motivation maintenance.","beginner"),
      q("mt4-49",pd,"ethical_dilemmas","A competent patient makes a decision you believe is harmful to their health.","How would you respect a harmful autonomous decision?","I would ensure the patient fully understands the risks and consequences through thorough education. I would explore their reasoning and address any misconceptions. I would document the informed refusal meticulously. Ultimately, competent patients have the right to make decisions others may view as harmful. My role is to inform, not to impose my values.","Respecting autonomous harmful decisions with thorough education.","intermediate"),
      q("mt4-50",ct,"first_shift","You complete your first independent shift.","How would you reflect on your first independent shift?","I would take time to process: What went well? What was challenging? What would I do differently? Who can I thank for their support? I would write brief reflections in my clinical journal, identify one skill to improve before my next shift, and recognize this milestone as evidence that I am capable. My first independent shift is just the beginning of a rewarding career.","Post-first-shift reflection and growth mindset.","beginner"),
    ]
  },
  {
    id: "mock-career-ethics-5",
    title: "Career Development & Professional Ethics Assessment",
    description: "Comprehensive assessment of professional development, ethical decision-making, career planning, and interpersonal skills for new graduate nurses.",
    category: "professional_development",
    difficulty: "intermediate",
    timeLimit: 55,
    supportsRandomization: true,
    questions: [
      q("mt5-1",pd,"ethical_dilemmas","A colleague confides they falsified a patient assessment.","How would you handle a colleague admitting to documentation falsification?","I would express the seriousness: 'I understand you may have felt pressured, but falsifying assessments puts patients at risk and could cost you your license. The correct assessment needs to be documented now. I strongly encourage you to self-report through the safety system.' If they refused, I would report it myself as it is a patient safety obligation.","Documentation falsification intervention.","intermediate"),
      q("mt5-2",pd,"professional_boundaries","A patient's family offers to pay you extra for additional care.","How would you handle an offer of payment for extra care?","I would decline: 'Every patient on this unit receives the same quality of care regardless of payment. I appreciate your concern for your family member, but I cannot accept payment. If you feel your loved one needs additional care, I can discuss with the care team about adjusting the plan.'","Equitable care principle with payment refusal.","beginner"),
      q("mt5-3",pd,"advocacy","A patient is being pressured by their family about medical decisions.","How would you support a patient facing family pressure?","I would ensure private time with the patient to assess their true wishes. I would ask: 'What do you want to do?' I would validate their autonomy and ensure they know the decision is ultimately theirs. I would facilitate a family meeting with the physician to align expectations while centering the patient's voice.","Patient autonomy protection from family pressure.","intermediate"),
      q("mt5-4",pd,"patient_communication","A patient newly diagnosed with cancer needs emotional support.","How would you support a newly diagnosed cancer patient?","I would provide a safe space to process their emotions, listen without judgment, validate their feelings as normal, avoid platitudes like 'everything will be fine,' provide factual information at their pace, connect them with oncology support services, and ensure they know they are not alone. I would follow up consistently.","Cancer diagnosis emotional support.","intermediate"),
      q("mt5-5",cn,"job_offer_negotiation","You are negotiating benefits as part of your job offer.","What benefits should a new nurse negotiate?","I would ask about: tuition reimbursement, certification exam fees, professional conference attendance, continuing education hours, retirement matching, health insurance options, flexible scheduling, signing bonus terms, and student loan repayment assistance. Total compensation value often exceeds base salary differences between offers.","Benefits negotiation awareness.","beginner"),
      q("mt5-6",cn,"probation_period","You want to make a positive impression during orientation.","What behaviors establish credibility during orientation?","Consistency in: arriving on time, completing assignments thoroughly, accepting feedback gracefully, asking thoughtful questions, maintaining a positive attitude, being a team player, following up on learning goals, and demonstrating progressive clinical competence. The most credibility-building behavior is consistent, safe patient care with honest communication about limitations.","Credibility-building during orientation.","beginner"),
      q("mt5-7",pd,"workplace_bullying","A group of experienced nurses excludes new graduates from social events.","How would you navigate exclusion by experienced staff?","I would focus on building professional relationships through competence, reliability, and a positive attitude. I would not change my professional behavior to gain social acceptance. I would seek connections with other new graduates and supportive staff. If exclusion extends to professional development opportunities, I would address it with management.","Professional focus despite social exclusion.","beginner"),
      q("mt5-8",pd,"ethical_dilemmas","A pharmaceutical representative offers you gifts to promote their products.","How would you handle pharmaceutical industry influence?","I would decline: 'I appreciate the information about your product, but I cannot accept gifts that could influence my clinical recommendations. My medication recommendations are based solely on evidence-based practice and what is best for my patients.' I would follow facility policy on pharmaceutical representative interactions.","Industry influence resistance.","beginner"),
      q("mt5-9",cn,"career_advancement","You want to build a professional network.","How would you build a nursing professional network?","I would join professional organizations, attend conferences, participate in unit committees, connect with nursing leaders on LinkedIn, maintain contact with nursing school classmates, and seek mentoring relationships. I would focus on genuine relationship building rather than transactional networking.","Professional networking strategies.","beginner"),
      q("mt5-10",pd,"patient_communication","A patient is frightened about going home after a hospital stay.","How would you address discharge anxiety?","I would explore their specific concerns: 'What worries you most about going home?' I would ensure thorough discharge education, verify they have support systems, arrange home health if needed, provide clear instructions for when to call the doctor or return to the ED, and follow up with a post-discharge phone call if available.","Discharge anxiety assessment and support.","beginner"),
      q("mt5-11",pd,"ethical_dilemmas","You discover that a treatment order may be motivated by financial rather than clinical reasons.","How would you address financially motivated treatment decisions?","I would focus on clinical evidence: 'I want to ensure this treatment is indicated based on clinical evidence. Can you help me understand the clinical rationale?' If I remained concerned, I would report through the compliance system. Financial incentives should never drive clinical decision-making.","Clinical rationale questioning for financially suspect orders.","advanced"),
      q("mt5-12",cn,"performance_evaluation","Your manager gives you a satisfactory rating but you expected exceeds expectations.","How would you discuss a disappointing evaluation rating?","I would ask for specific examples: 'I appreciate the feedback. Can you help me understand what specific behaviors or outcomes would have warranted a higher rating? I want to establish clear expectations for the next period.' I would not argue or become defensive but would use the information to create targeted improvement goals.","Constructive response to disappointing evaluation.","beginner"),
      q("mt5-13",pd,"advocacy","A patient needs a medical device they cannot afford.","How would you help a patient access an unaffordable medical device?","I would research manufacturer assistance programs, contact medical equipment donation organizations, involve social work for community resources, explore insurance appeal processes, investigate charitable care programs, and ensure the physician documents medical necessity thoroughly. No patient should go without needed medical devices due to financial barriers.","Medical device access advocacy.","intermediate"),
      q("mt5-14",pd,"professional_boundaries","You feel burnout affecting your patient care quality.","How would you recognize and address burnout?","I would identify the signs: emotional exhaustion, depersonalization, reduced accomplishment, dreading work, and physical symptoms. I would take action: use EAP counseling, discuss workload with management, implement self-care strategies, set work-life boundaries, and consider whether a unit or role change would help. Addressing burnout protects both my wellbeing and patient safety.","Burnout recognition and active intervention.","intermediate"),
      q("mt5-15",cn,"career_advancement","You are considering pursuing a DNP degree.","How would you evaluate whether a DNP is right for you?","I would consider: Do I want advanced clinical practice (NP), leadership, education, or research? Can I manage the time and financial commitment? Does a DNP align with my career goals better than an MSN? I would talk to DNP graduates about their experience and career outcomes. I would ensure adequate clinical experience before starting a doctoral program.","DNP program evaluation framework.","intermediate"),
      q("mt5-16",pd,"ethical_dilemmas","A patient is being abused by a family member who visits the hospital.","How would you handle suspected abuse by a hospital visitor?","I would ensure the patient's immediate safety, ask to speak with the patient privately, assess for abuse indicators, document findings objectively, notify the physician and social work, follow mandatory reporting requirements, and implement safety measures including restricted visitation if needed. Patient safety is non-negotiable.","Abuse identification and mandatory reporting.","advanced"),
      q("mt5-17",pd,"patient_communication","A dying patient wants to discuss their fear of death.","How would you talk to a patient about dying?","I would listen with genuine presence, not rushing to comfort or redirect. I would ask open-ended questions: 'What are you most afraid of?' I would validate their fears without dismissing them. I would offer chaplain services, ensure their wishes are documented, and maintain compassionate honesty. Being present with dying patients is one of nursing's most sacred responsibilities.","Honest conversation about death with compassionate presence.","advanced"),
      q("mt5-18",cn,"job_offer_negotiation","You want to compare total compensation between offers.","How would you calculate total compensation beyond salary?","I would include: base salary, shift differentials, overtime potential, health insurance value, retirement contributions, tuition reimbursement, certification fees, paid time off days, sick leave, professional development funding, and any sign-on bonus. A position paying $2/hour less but with $10,000 tuition reimbursement may be worth significantly more long-term.","Total compensation calculation methodology.","beginner"),
      q("mt5-19",pd,"workplace_bullying","You witness a nurse being publicly humiliated by a physician.","How would you intervene as a bystander to physician-nurse abuse?","I would speak up: 'Can we take this conversation to a private area?' or 'I think we can discuss this more productively in private.' After the incident, I would check on my colleague, encourage them to report the behavior, and report it myself if I witnessed a pattern. Physician-nurse abuse should never be normalized.","Active bystander intervention against interdisciplinary abuse.","intermediate"),
      q("mt5-20",cn,"career_advancement","You want to develop expertise in a clinical area.","How would you systematically develop clinical expertise?","I would create a development plan: identify learning resources, seek mentorship from experts, attend relevant conferences, pursue specialty certification, engage in journal clubs, participate in research, and set progressive competency goals. I would document my expertise development for career advancement purposes.","Systematic expertise development plan.","beginner"),
      q("mt5-21",pd,"ethical_dilemmas","A patient asks you to help them end their life.","How would you respond to a patient's request for assisted death?","I would respond with compassion: 'I hear that you are suffering. Can you help me understand what is making life feel unbearable right now?' I would assess for depression, ensure adequate pain management, involve palliative care, and provide emotional support. I would follow my state's laws regarding end-of-life options and ensure the patient has access to appropriate resources and counseling.","Compassionate response to end-of-life requests.","advanced"),
      q("mt5-22",pd,"advocacy","A policy change negatively affects patient care quality.","How would you advocate against a harmful policy change?","I would gather objective data about the policy's impact on patient outcomes, present findings to management with specific concerns, engage shared governance processes, collaborate with colleagues who share the concern, and propose alternative solutions. I would use evidence rather than emotion to make my case.","Data-driven policy advocacy.","intermediate"),
      q("mt5-23",cn,"probation_period","Your orientation schedule is disrupted by staffing needs.","How would you manage orientation disruption?","I would communicate the impact to my manager: 'I understand staffing is a priority. However, my orientation is being significantly disrupted, which may affect my readiness for independent practice. Can we discuss how to balance staffing needs with completing my essential orientation competencies?'","Orientation protection advocacy.","beginner"),
      q("mt5-24",pd,"patient_communication","A patient with intellectual disability needs informed consent.","How would you ensure informed consent for patients with intellectual disabilities?","I would adapt communication to the patient's comprehension level, use simple language and visual aids, involve their legal guardian if they have one, allow extra time for processing information, verify understanding through adapted teach-back, and involve the ethics committee if capacity is uncertain. Every person deserves to be included in their care decisions to the extent possible.","Adaptive informed consent for intellectual disability.","intermediate"),
      q("mt5-25",cn,"career_advancement","You want to transition from staff nurse to clinical nurse specialist.","How would you pursue a CNS career?","I would gain extensive clinical expertise in my specialty, pursue a CNS-focused graduate program, develop skills in education, consultation, and research, publish and present in my area of expertise, and network with current CNSs. The CNS role requires advanced clinical knowledge combined with systems-level thinking and leadership.","Clinical nurse specialist career pathway.","intermediate"),
      q("mt5-26",pd,"ethical_dilemmas","You discover a colleague is diverting medications.","How would you handle suspected drug diversion?","I would report my observations to my manager and pharmacy immediately—drug diversion is a patient safety and legal issue that I cannot address alone. I would document specific observations: missing medications, frequent bathroom trips, behavior changes, and medication discrepancies. I would not confront the colleague directly, as this is an investigation that requires proper protocol.","Drug diversion reporting obligation.","advanced"),
      q("mt5-27",pd,"professional_boundaries","A patient's gift triggers a personal emotional response.","How would you manage personal emotional triggers in nursing?","I would acknowledge the emotional response privately, seek processing support through debriefing or counseling, develop coping strategies for future triggers, and ensure my emotional state does not compromise patient care. Self-awareness about emotional triggers is a professional skill that strengthens rather than weakens nursing practice.","Emotional trigger self-management.","intermediate"),
      q("mt5-28",cn,"performance_evaluation","You want to advocate for a promotion during your evaluation.","How would you position yourself for advancement?","I would prepare evidence: 'I have consistently demonstrated leadership through [specific examples], achieved [measurable outcomes], and developed expertise in [specific areas]. I believe I am ready for advancement to [specific role]. What criteria would need to be met, and how can we create a timeline for this progression?'","Evidence-based promotion advocacy.","intermediate"),
      q("mt5-29",pd,"patient_communication","A patient is struggling with body image changes from treatment.","How would you support body image concerns?","I would validate their feelings: 'Changes in your body from treatment are real losses, and it is normal to grieve them.' I would explore their specific concerns, provide resources for coping strategies, refer to psychology or support groups, and help them find ways to maintain self-identity beyond physical appearance. I would never minimize their concerns.","Body image support without minimization.","intermediate"),
      q("mt5-30",pd,"ethical_dilemmas","A research study participant asks you about the study results before publication.","How would you handle premature result disclosure requests?","I would explain: 'I understand your curiosity about the study results. However, sharing results before they are finalized and published could provide inaccurate information and violate research protocols. The research team will share findings with all participants once the study is complete. I can help you connect with the principal investigator if you have specific concerns.'","Research confidentiality maintenance.","intermediate"),
      q("mt5-31",cn,"career_advancement","You want to develop your speaking and presentation skills.","How would you develop nursing presentation skills?","I would start small: present patient cases during unit meetings, then progress to poster presentations at local conferences, then to oral presentations at regional events. I would take a public speaking course, join Toastmasters, practice with supportive colleagues, and seek feedback after each presentation. Presentation skills are essential for career advancement in any nursing role.","Progressive presentation skill development.","beginner"),
      q("mt5-32",pd,"advocacy","A patient needs end-of-life care but the family insists on aggressive treatment.","How would you navigate family-patient conflict about end-of-life care?","I would ensure the patient's wishes are documented and central to the discussion. I would facilitate a family meeting with the palliative care team, help the family understand the patient's perspective, provide information about comfort care versus aggressive treatment outcomes, and involve the ethics committee if the conflict cannot be resolved through communication.","End-of-life family conflict mediation.","advanced"),
      q("mt5-33",pd,"patient_communication","A patient from a different cultural background has health beliefs that differ from Western medicine.","How would you provide culturally sensitive care?","I would ask about their beliefs respectfully, incorporate safe cultural practices into the care plan, explain Western medical approaches without dismissing their beliefs, use cultural liaisons when available, and find common ground. I would never force Western medical views but would ensure they understand the medical perspective for informed decision-making.","Cultural belief integration with medical care.","intermediate"),
      q("mt5-34",cn,"probation_period","You want to exceed expectations during your final probation review.","What actions demonstrate exceptional performance during probation?","I would demonstrate: clinical growth with documented evidence, positive patient and family feedback, reliable attendance and punctuality, proactive problem-solving, team support beyond my assignment, committee participation, continuing education, and a documented professional development plan. Exceeding expectations means contributing to the unit, not just meeting individual standards.","Exceptional probation performance demonstration.","beginner"),
      q("mt5-35",pd,"ethical_dilemmas","You are asked to care for a patient whose beliefs you find deeply objectionable.","How would you provide care despite fundamental value disagreements?","I would separate my personal values from my professional obligation. Every patient deserves competent, compassionate care regardless of their beliefs or actions. If my personal feelings significantly impair my ability to provide equitable care, I would request reassignment without judgment. I would process my feelings through appropriate channels.","Value separation for equitable care.","advanced"),
      q("mt5-36",pd,"professional_boundaries","You are offered a side job from a patient's family member.","How would you handle employment offers from patients' families?","I would decline: 'I appreciate the offer, but accepting employment from a patient's family would create a conflict of interest with my professional responsibilities. I need to maintain my independence as your family member's nurse.' I would report the offer to my manager if it raised ethical concerns.","Professional independence maintenance.","beginner"),
      q("mt5-37",cn,"career_advancement","You want to make a meaningful contribution to nursing science.","How would you contribute to nursing knowledge?","I would start by identifying a clinical question from my practice, review existing literature, participate in research studies, present findings at conferences, publish case reports or quality improvement results, and pursue graduate education in my area of interest. Every bedside nurse can contribute to nursing science through systematic inquiry.","Clinical nurse contribution to nursing science.","intermediate"),
      q("mt5-38",pd,"advocacy","A elderly patient is being discharged to a facility they do not want to go to.","How would you advocate for patient placement preferences?","I would ensure the patient's preferences are documented and communicated to the discharge planning team. I would explore alternative placement options, involve social work in identifying preferred facilities, and advocate during team meetings: 'The patient has expressed a clear preference for [facility]. Can we explore whether this placement is feasible?'","Patient placement preference advocacy.","beginner"),
      q("mt5-39",pd,"patient_communication","A patient is receiving conflicting information from different providers.","How would you help a patient with conflicting provider information?","I would acknowledge the confusion: 'I understand how frustrating it is to hear different things from different people. Let me help sort this out.' I would identify the specific conflicts, communicate them to the primary provider, request a unified care plan, and arrange a care conference if needed. Patients deserve consistent, aligned communication.","Conflicting information resolution advocacy.","intermediate"),
      q("mt5-40",cn,"performance_evaluation","You want to set a meaningful 5-year development plan.","How would you create a 5-year professional development plan?","Year 1: Build clinical competence, achieve independent practice. Year 2: Pursue specialty certification, join a committee. Year 3: Precept new graduates, present at a conference. Year 4: Begin graduate education or advanced leadership roles. Year 5: Achieve advanced practice status or leadership position. Each year builds on the previous one while remaining flexible for opportunities.","Progressive 5-year development plan.","beginner"),
      q("mt5-41",pd,"ethical_dilemmas","A patient's insurance runs out during critical treatment.","How would you advocate for continued care despite insurance loss?","I would involve social work immediately, explore hospital charity care programs, contact the insurance company for extension appeals, research government assistance programs, and communicate the clinical necessity of continued treatment to the administrative team. I would document the medical necessity thoroughly. No patient should be abandoned during critical treatment due to insurance status.","Insurance advocacy for treatment continuity.","intermediate"),
      q("mt5-42",pd,"workplace_bullying","A manager creates a toxic work environment through favoritism.","How would you address management favoritism?","I would document specific examples of unequal treatment, request a meeting with the manager to discuss equitable treatment, and escalate to HR if direct conversation fails. I would focus on professional impact rather than personal feelings: 'I have noticed that education opportunities are not distributed equitably. Can we discuss how to ensure all staff have equal access?'","Documented favoritism complaint with professional focus.","intermediate"),
      q("mt5-43",cn,"career_advancement","You want to develop informatics skills alongside clinical practice.","How would you integrate informatics into your clinical career?","I would pursue informatics training through online courses, volunteer for EHR optimization committees, learn about clinical decision support tools, understand data analytics in healthcare, and develop competency with health information technology. Informatics skills are increasingly valuable in every nursing role—not just for informaticists.","Informatics skill development for clinical nurses.","beginner"),
      q("mt5-44",pd,"patient_communication","A patient is in denial about their alcohol dependence.","How would you approach a patient in denial about substance use?","I would use motivational interviewing: express empathy, develop discrepancy between their values and behavior, roll with resistance rather than confronting, and support self-efficacy. I would say: 'I am not here to judge. I am concerned about how alcohol might be affecting your health. What are your thoughts about your drinking?' Meeting patients where they are is more effective than confrontation.","Motivational interviewing for substance use denial.","intermediate"),
      q("mt5-45",cn,"job_offer_negotiation","You are considering a position that requires relocation.","How would you evaluate a relocation opportunity for career advancement?","I would weigh: career growth potential versus personal disruption, cost of living differences, professional network impact, family considerations, facility reputation, long-term career trajectory, and whether the opportunity aligns with my 5-year plan. I would negotiate relocation assistance and visit the area before deciding.","Comprehensive relocation opportunity evaluation.","intermediate"),
      q("mt5-46",pd,"ethical_dilemmas","You are caring for a minor whose parents refuse treatment.","How would you handle parental refusal of treatment for a minor?","I would ensure the parents understand the treatment's necessity and consequences of refusal. For non-emergent situations, I would involve the ethics committee and social work. For life-threatening emergencies, I would follow legal protocols—most states allow emergency treatment of minors regardless of parental consent. I would document everything meticulously.","Minor treatment refusal legal and ethical navigation.","advanced"),
      q("mt5-47",pd,"advocacy","A patient needs a reasonable workplace accommodation for their disability.","How would you support a patient needing workplace accommodations?","I would provide appropriate clinical documentation, educate the patient about their rights under the ADA, connect them with vocational rehabilitation services, and ensure the discharge plan includes return-to-work planning. I would document functional limitations and capabilities clearly to support the accommodation request.","ADA accommodation support and documentation.","intermediate"),
      q("mt5-48",cn,"career_advancement","You are considering leaving nursing entirely.","How would you evaluate a career change from nursing?","I would first assess whether the issue is with nursing itself or with my current position, specialty, or work environment. I would explore different nursing roles before leaving the profession. I would consider what transferable skills nursing has given me. If I still want to leave, I would plan the transition thoughtfully—many nursing skills transfer to other fields.","Thoughtful career change evaluation.","intermediate"),
      q("mt5-49",pd,"patient_communication","A patient wants to refuse hospice because they see it as giving up.","How would you reframe hospice care for a resistant patient?","I would reframe: 'Hospice is not about giving up—it is about focusing on what matters most to you: comfort, quality time with family, and living as fully as possible. Hospice actually provides more support, not less. It is choosing to live your remaining time with dignity and comfort. Would you like to speak with the hospice team to learn more?'","Hospice reframing from giving up to living fully.","intermediate"),
      q("mt5-50",cn,"career_advancement","You want to leave a lasting positive impact on your unit.","How would you create a lasting positive contribution?","I would identify a quality improvement opportunity, develop an evidence-based solution, implement it with team buy-in, measure outcomes, and share results. I would mentor other nurses, contribute to unit culture, and participate in policy development. Lasting impact comes from sustainable changes that improve patient care and team function, not from grand gestures.","Sustainable quality contribution for lasting impact.","intermediate"),
    ]
  },
];
